  function contDisponibil(bTitle, contName, excludeId) { var a = contAlocat(bTitle, contName); if (isNaN(a)) return NaN; return a - contConsumat(bTitle, contName, excludeId); }
  function bugetAlocat(bTitle) { var b = bugetInfo(bTitle); return b && b.SumaAlocata != null && b.SumaAlocata !== "" ? Number(b.SumaAlocata) : NaN; }
  function bugetConsumat(bTitle, excludeId) { return excludeContrib(_consumatBuget, bKey(bTitle), excludeId, function (t) { return bKey(t[CONFIG.FIELDS.BUGET]); }); }
  function bugetDisponibil(bTitle, excludeId) { var a = bugetAlocat(bTitle); if (isNaN(a)) return NaN; return a - bugetConsumat(bTitle, excludeId); }

  /* ---- biblioteca: folder perioada + upload ---- */
  function ensureFolder(label) {
    var rel = _siteRel + "/" + CONFIG.LIB.DOCS + "/" + label;
    return spGet("/_api/web/GetFolderByServerRelativeUrl('" + encodeURIComponent(rel) + "')?$select=Exists")
      .then(function (j) { if (j.d && j.d.Exists) return rel; throw 0; })
      .catch(function () {
        return spPost("/_api/web/folders", { "__metadata": { "type": "SP.Folder" }, "ServerRelativeUrl": rel }).then(function () { return rel; });
      });
  }
  // Encodare pentru literal OData SharePoint: dubleaza apostroful ('') APOI encodeURIComponent.
  // Fara asta, nume cu apostrof (ex. „COMINC'S") dau 400 InvalidClientQueryException.
  function spLit(s) { return encodeURIComponent(String(s == null ? "" : s).replace(/'/g, "''")); }
  function uploadFile(folderRel, fileName, arrayBuffer) {
    return digest().then(function (dg) {
      var url = _webUrl + "/_api/web/GetFolderByServerRelativeUrl('" + spLit(folderRel) +
        "')/Files/add(url='" + spLit(fileName) + "',overwrite=true)";
      return fetch(url, {
        method: "POST", credentials: "same-origin",
        headers: { "Accept": "application/json;odata=verbose", "X-RequestDigest": dg }, body: arrayBuffer
      });
    }).then(function (r) { if (!r.ok) return r.text().then(function (t) { throw new Error("upload " + r.status + " " + t); }); return r.json(); });
  }
  function readArrayBuffer(file) {
    return new Promise(function (res, rej) {
      var rd = new FileReader(); rd.onload = function () { res(rd.result); }; rd.onerror = function () { rej(rd.error); }; rd.readAsArrayBuffer(file);
    });
  }
  function readBase64(file) {
    return new Promise(function (res, rej) {
      var rd = new FileReader(); rd.onload = function () { res(String(rd.result).split(",")[1]); }; rd.onerror = function () { rej(rd.error); }; rd.readAsDataURL(file);
    });
  }
  function spGetBuffer(rel) {
    return fetch(_webUrl + rel, { credentials: "same-origin" })
      .then(function (r) { if (!r.ok) throw new Error("GET " + rel + " " + r.status); return r.arrayBuffer(); });
  }
  function listFolderFiles(folderRel) {
    // cb=timestamp: spargem cache-ul ca lista sa includa fisierele tocmai urcate (fara refresh de pagina)
    return spGet("/_api/web/GetFolderByServerRelativeUrl('" + encodeURIComponent(folderRel) +
      "')/Files?$select=Name,ServerRelativeUrl&$top=2000&cb=" + Date.now()).then(function (j) { return j.d.results; });
  }
  // Ia UN fisier dupa nume (rapid) — pt. tranzactiile cu nume cunoscute, ca sa nu mai listam tot folderul.
  function fetchOneFile(folderRel, name) {
    var rel = folderRel + "/" + name;
    return spGet("/_api/web/GetFileByServerRelativeUrl('" + spLit(rel) + "')?$select=Name,ServerRelativeUrl")
      .then(function (j) { return (j && j.d && j.d.ServerRelativeUrl) ? { Name: j.d.Name, ServerRelativeUrl: j.d.ServerRelativeUrl } : null; })
      .catch(function () { return null; });
  }
  // [b99] Listeaza numele subfolderelor dintr-un folder parinte (ex. toate folderele de perioada din biblioteca Documente).
  function listSubfolders(parentRel) {
    return spGet("/_api/web/GetFolderByServerRelativeUrl('" + encodeURIComponent(parentRel) + "')/Folders?$select=Name&$top=2000&cb=" + Date.now())
      .then(function (j) { return ((j.d && j.d.results) || []).map(function (f) { return f.Name; }); })
      .catch(function () { return []; });
  }
  // [b99] Foldere candidate pentru o perioada, INCLUSIV variantele redenumite: orice folder care incepe cu „<dataStart>_”
  //   (ex. „2026-06-10_in-curs”, „2026-06-10_2026-06-12”, „2026-06-10_2026-06-13”). Asa gasim documentele chiar daca
  //   folderul a primit alt sufix de data cand „Data final” a fost candva setata (MoveTo pe foldere a esuat istoric — vezi b45).
  function expandedPeriodFolders(p) {
    var base = periodLabelsFor(p);
    if (!p || !p.DataStart) return Promise.resolve(base);
    var prefix = isoDate(p.DataStart) + "_";
    return listSubfolders(_siteRel + "/" + CONFIG.LIB.DOCS).then(function (names) {
      var out = base.slice();
      (names || []).forEach(function (nm) { if (nm && nm.indexOf(prefix) === 0 && out.indexOf(nm) < 0) out.push(nm); });
      return out;
    }).catch(function () { return base; });
  }
  // [b99] Comaseaza toate folderele „<dataStart>_…” ale perioadei intr-unul singur (canonic = targetLabel sau periodLabel(p)).
  //   Muta fisierele din folderele in plus in folderul canonic (suprascrie), apoi sterge folderele golite. Idempotent.
  function consolidatePeriodFolders(p, targetLabel) {
    if (!p || !p.DataStart) return Promise.resolve({ moved: 0, folders: 0 });
    var canon = targetLabel || periodLabel(p);
    var canonRel = _siteRel + "/" + CONFIG.LIB.DOCS + "/" + canon;
    var prefix = isoDate(p.DataStart) + "_";
    return ensureFolder(canon).then(function () { return listSubfolders(_siteRel + "/" + CONFIG.LIB.DOCS); }).then(function (names) {
      var extras = (names || []).filter(function (nm) { return nm && nm.indexOf(prefix) === 0 && nm !== canon; });
      if (!extras.length) return { moved: 0, folders: 0 };
      var moved = 0, chain = Promise.resolve();
      extras.forEach(function (lb) {
        var srcRel = _siteRel + "/" + CONFIG.LIB.DOCS + "/" + lb;
        chain = chain.then(function () {
          return listFolderFiles(srcRel).catch(function () { return []; }).then(function (files) {
            var c2 = Promise.resolve();
            (files || []).forEach(function (f) {
              c2 = c2.then(function () {
                return digest().then(function (dg) {
                  return rawSend("/_api/web/GetFileByServerRelativeUrl('" + spLit(f.ServerRelativeUrl) + "')/moveto(newurl='" + spLit(canonRel + "/" + f.Name) + "',flags=1)", "POST", dg).then(function () { moved++; });
                }).catch(function (e) { console.warn("consolidate move", f.Name, e); });
              });
            });
            return c2.then(function () {   // folderul ramas gol -> recycle
              return digest().then(function (dg) { return rawSend("/_api/web/GetFolderByServerRelativeUrl('" + spLit(srcRel) + "')/recycle()", "POST", dg).catch(function () {}); });
            });
          });
        });
      });
      return chain.then(function () { return { moved: moved, folders: extras.length }; });
    }).catch(function (e) { console.warn("consolidatePeriodFolders", e); return { moved: 0, folders: 0 }; });
  }
  // Redenumeste folderul perioadei (start_(deschis) -> start_end) la inchidere.
  function renameFolder(oldRel, newRel) {
    if (oldRel === newRel) return Promise.resolve(newRel);
    return spGet("/_api/web/GetFolderByServerRelativeUrl('" + spLit(oldRel) + "')?$select=Exists")
      .then(function (j) { return (j.d && j.d.Exists); })
      .then(function (exists) {
        if (!exists) return ensureFolder(newRel.split("/").pop());
        // [v2-b45] la FOLDERE, MoveTo nu accepta „flags” (InvalidClientQueryException 400) — de aceea
        // folderul perioadei nu se redenumea la inchidere si raman „_in-curs” cu fisierele in el.
        return spPost("/_api/web/GetFolderByServerRelativeUrl('" + spLit(oldRel) +
          "')/MoveTo(newurl='" + spLit(newRel) + "')").then(function () { return newRel; });
      }).catch(function () { return ensureFolder(newRel.split("/").pop()); });
  }

