    fs.addEventListener("click", toggleFullscreen); hd.appendChild(fs);

    var psel = document.createElement("select"); psel.className = APP_ID + "-period-sel"; psel.id = APP_ID + "-psel";
    psel.addEventListener("change", function () {
      var p = null; for (var i = 0; i < _periods.length; i++) if (String(_periods[i].Id) === psel.value) p = _periods[i];
      _activePeriod = p; _lastReconcileBlob = null; loadTrx().then(function () { render(); if (_tab !== "acasa") mountTab(_tab); });
    });
    hd.appendChild(psel);

    var addP = ce("button", "iconbtn"); addP.type = "button"; txt(addP, "+"); addP.title = "Perioada noua";
    addP.addEventListener("click", openNewPeriod); hd.appendChild(addP);

    var mngP = ce("button", "iconbtn"); mngP.type = "button"; txt(mngP, "🗂"); mngP.title = "Gestioneaza / sterge perioade si fisiere AI";
    mngP.addEventListener("click", openManage); hd.appendChild(mngP);
    app.appendChild(hd);

    // body/main
    var body = ce("div", "body");
    var main = ce("div", "main");

    var tb = ce("div", "toolbar");
    var searchWrap = ce("div", "searchwrap");
    var search = document.createElement("input"); search.className = APP_ID + "-search"; search.placeholder = "Cauta furnizor, descriere, cod, suma... (in toate perioadele)";
    var searchX = ce("button", "search-x"); searchX.type = "button"; txt(searchX, "✕"); searchX.title = "Sterge cautarea"; searchX.style.display = "none";
    search.addEventListener("input", function () { _search = normTxt(search.value).trim(); searchX.style.display = search.value ? "" : "none"; applyFilters(); });
    searchX.addEventListener("click", function () { search.value = ""; _search = ""; searchX.style.display = "none"; applyFilters(); search.focus(); });
    searchWrap.appendChild(search); searchWrap.appendChild(searchX);
    tb.appendChild(searchWrap);

    // Filtrele secundare stau ascunse intr-un panou (palnie). Pe bara ramane doar search + butoanele.
    var fScope = document.createElement("select"); fScope.className = APP_ID + "-btn " + APP_ID + "-scope"; fScope.id = APP_ID + "-scope";
    fScope.title = "Unde se cauta: in toate perioadele (implicit) sau intr-o singura perioada";
    fScope.addEventListener("change", function () { _searchScope = fScope.value; applyFilters(); });

    var fStatus = mkFilterSelect("Status", ["Draft", "Finalizat"], "status");
    var fApr = mkFilterSelect("Aprobare", CONFIG.APPROVAL_STATES, "aprobare");

    var fNrDoc = document.createElement("input"); fNrDoc.type = "text"; fNrDoc.className = APP_ID + "-filt-input"; fNrDoc.placeholder = "Nr. document";
    fNrDoc.addEventListener("input", function () { _filters.nrdoc = normTxt(fNrDoc.value).trim(); applyFilters(); });
    var fCod = document.createElement("input"); fCod.type = "text"; fCod.className = APP_ID + "-filt-input"; fCod.placeholder = "Cod furnizor";
    fCod.addEventListener("input", function () { _filters.cod = normTxt(fCod.value).trim(); applyFilters(); });

    var filterWrap = ce("div", "filterwrap");
    var bFilt = ce("button", "btn filt-btn"); bFilt.type = "button"; bFilt.title = "Filtre cautare";
    var fIc = v2icon("filter"); fIc.setAttribute("width", "13"); fIc.setAttribute("height", "13"); bFilt.appendChild(fIc);
    var bFiltLbl = document.createElement("span"); bFiltLbl.textContent = "Filtre"; bFilt.appendChild(bFiltLbl);
    var bFiltDot = ce("span", "filt-dot"); bFiltDot.id = APP_ID + "-filt-dot"; bFiltDot.style.display = "none"; bFilt.appendChild(bFiltDot);
    filterWrap.appendChild(bFilt);

    var panel = ce("div", "filt-panel"); panel.id = APP_ID + "-filt-panel";
    var pTitle = ce("div", "filt-panel-h"); txt(pTitle, "Filtre"); panel.appendChild(pTitle);
    panel.appendChild(fScope);
    panel.appendChild(fStatus);
    panel.appendChild(fApr);
    panel.appendChild(fNrDoc);
    panel.appendChild(fCod);
    var bReset = ce("button", "btn ghost filt-reset"); txt(bReset, "Reset filtre");
    bReset.addEventListener("click", function () {
      _filters.status = []; _filters.aprobare = []; _filters.nrdoc = ""; _filters.cod = ""; _searchScope = "all";
      fStatus.value = ""; fApr.value = ""; fNrDoc.value = ""; fCod.value = ""; fScope.value = "all";
      applyFilters();
    });
    panel.appendChild(bReset);
    filterWrap.appendChild(panel);

    bFilt.addEventListener("click", function (e) { e.stopPropagation(); panel.classList.toggle("open"); });
    document.addEventListener("click", function (ev) { if (!filterWrap.contains(ev.target)) panel.classList.remove("open"); });
    tb.appendChild(filterWrap);

    var bBatch = ce("button", "btn"); txt(bBatch, "+ Import multiplu"); bBatch.title = "Mai multe fisiere -> AI -> In curs de clarificare"; bBatch.addEventListener("click", openBatchImport); tb.appendChild(bBatch);
    var bJrn = ce("button", "btn"); txt(bJrn, "📒 Jurnal"); bJrn.title = "Antet jurnal (CM Clerk), reconciliere CSV, export ZIP"; bJrn.addEventListener("click", openJurnal); tb.appendChild(bJrn);
    var bSet = ce("button", "btn"); txt(bSet, "⚙ Setari"); bSet.title = "Bugete, aprobatori, jurnal erori"; bSet.addEventListener("click", function () { mountTab("setari"); }); tb.appendChild(bSet);
    var bNew = ce("button", "btn accent"); txt(bNew, "+ Tranzactie"); bNew.addEventListener("click", function () { openEdit(null); }); tb.appendChild(bNew);
