    if (_editing[k] && CONFIG.FIELDS.SPV_EXCEPT && _editing[CONFIG.FIELDS.SPV_EXCEPT]) _editing[CONFIG.FIELDS.SPV_EXCEPT] = false;   // [b172] cererea manuala scoate exceptia (se exclud reciproc)
    refreshBonWarn(); refreshSpvUI();
