      for (var i = len - 22; i >= lim; i--) { if (dv.getUint32(i, true) === 0x06054b50) { eocd = i; break; } }
      if (eocd < 0) return {};
      var cdCount = dv.getUint16(eocd + 10, true), cdOff = dv.getUint32(eocd + 16, true);
      var entries = [], p = cdOff, dec = new TextDecoder();
      for (var n = 0; n < cdCount && p + 46 <= len; n++) {
        if (dv.getUint32(p, true) !== 0x02014b50) break;
        var method = dv.getUint16(p + 10, true), compSize = dv.getUint32(p + 20, true);
        var nameLen = dv.getUint16(p + 28, true), extraLen = dv.getUint16(p + 30, true), cmtLen = dv.getUint16(p + 32, true);
        var lhOff = dv.getUint32(p + 42, true);
        var name = dec.decode(u8.subarray(p + 46, p + 46 + nameLen));
        entries.push({ method: method, compSize: compSize, lhOff: lhOff, name: name });
        p += 46 + nameLen + extraLen + cmtLen;
      }
