    while ((m = re.exec(xml))) { var inner = m[1], t = "", tm, tre = /<t\b[^>]*>([\s\S]*?)<\/t>/g; while ((tm = tre.exec(inner))) t += tm[1]; out.push(xlsxDecode(t)); }
