    var _stmtClose = (_lastStmtMeta && String(_lastStmtMeta.periodId) === String(p.Id) && _lastStmtMeta.dataFinal) ? isoDate(_lastStmtMeta.dataFinal) : null;
    var fld = ce("div", "field"); var lab = document.createElement("label"); txt(lab, "Data închiderii"); fld.appendChild(lab);
