      var hl = document.createElement("div"); hl.style.cssText = "font-size:11px;font-weight:700;letter-spacing:.04em;text-transform:uppercase;color:var(--v-ink3, #71737f);margin-bottom:5px;"; txt(hl, label); g.appendChild(hl);
      items.forEach(function (msg) {
        var r = document.createElement("div"); r.style.cssText = "display:flex;gap:8px;align-items:flex-start;padding:4px 0;font-size:12.8px;line-height:1.45;";
        var ic = document.createElement("span"); ic.style.cssText = "flex:0 0 auto;color:" + col + ";font-weight:700;"; txt(ic, kind === "err" ? "✖" : "⚠"); r.appendChild(ic);
        var tx2 = document.createElement("span"); tx2.style.color = "var(--v-ink2, #444)"; txt(tx2, msg); r.appendChild(tx2);
        g.appendChild(r);
      });
      return g;
