      var l = document.createElement("span"); l.style.color = "var(--v-ink2, #555)"; txt(l, label); r.appendChild(l);
      var v = document.createElement("span"); v.style.cssText = "text-align:right;" + (strong ? "font-weight:700;color:var(--v-ink, #1c1d26);" : "color:var(--v-ink2, #555);"); txt(v, val); r.appendChild(v);
