        try { var hf = document.createElement("div"); hf.style.cssText = "font-size:11px;color:var(--c-muted);margin:0 0 5px;"; txt(hf, "Cautate in: " + (scannedLabels.length ? scannedLabels.join(", ") : "—")); out.appendChild(hf); } catch (eHf) {}
        // [b110] Mai multe foldere REALE pentru aceeasi perioada? -> buton de comasare (canonic). Numaram folderele
