      function inWindow(t) { var td = t.Data ? new Date(t.Data).getTime() : NaN; return isNaN(td) ? true : td <= cutoff; }
      var matched = {}; (lr.matchedIds || []).forEach(function (id) { matched[String(id)] = 1; });
      // [b63] ancora = soldul initial al EXTRASULUI (banca reala la inceputul ferestrei), nu antetul jurnalului.
      // Astfel reportul (antet > extras initial, normal la reportare) NU mai apare ca diferenta —
      // diferenta ramane DOAR pentru anomalii reale (bon lipsa, suma gresita, extras partial).
      var start = !isNaN(sm.soldInitial) ? Number(sm.soldInitial) : periodSoldBanca(p), intrariW = 0, iesiriW = 0;
      var dupaExtras = [], dupaS = 0;       // dupa fereastra extrasului — in afara verificarii
      var impr = [], imprS = 0;             // [b62] marcate „din imprestul trecut" — decontate anterior, EXCLUSE din calcul
