        if (!inWindow(t)) { dupaExtras.push({ t: t, io: in0 ? 1 : -1 }); dupaS += (in0 ? 1 : -1) * Number(t.Suma || 0); return; }
        if (in0) intrariW += Number(t.Suma || 0); else iesiriW += Number(t.Suma || 0);
        if (matched[String(t.Id)]) return;
