      kvInto(vsKv, "− Iesiri jurnal pana la " + (sm.dataFinal ? fmtDate(sm.dataFinal, "dd.mm.yyyy") : "—"), fmtBani(iesiriW) + " " + CONFIG.CURRENCY);
      kvInto(vsKv, "+ In jurnal, dar NU pe extras (" + neapar.length + ")", fmtBani(neaparS) + " " + CONFIG.CURRENCY);
      if (blocS) kvInto(vsKv, "· din care blocate pe extras — pending, OK", fmtBani(blocS) + " " + CONFIG.CURRENCY);
