            confirmLabel: "Da, scoate flag-ul", cancelLabel: "Renunta",
            onConfirm: function () {
              fixTPE.disabled = true; txt(fixTPE, "Scot…");
              getEntityType(CONFIG.LISTS.TRX).then(function (et) {
                var ch = Promise.resolve();
                trecutPeExtras.forEach(function (t) {
                  ch = ch.then(function () {
                    var b = { "__metadata": { "type": et } }; b[CONFIG.FIELDS.IMPREST_TRECUT] = false;
                    return spPost("/_api/web/lists/getbytitle('" + CONFIG.LISTS.TRX + "')/items(" + t.Id + ")", b, { "X-HTTP-Method": "MERGE", "IF-MATCH": "*" })
                      .catch(function (e) { console.warn("scoatere imprest trecut", t.Id, e); });
                  });
                });
                return ch;
              }).then(function () {
                try { logEvent("actiune", "Scoase „din imprestul trecut” (decontate pe extras): " + trecutPeExtras.map(function (t) { return "#" + t.Id; }).join(", ")); } catch (eL) {}
                toast("Scoase din „imprestul trecut” (" + trecutPeExtras.length + ").", "success");
                return loadTrx().then(render);
              }).then(function () {
                if (_stmtAccum.rows && _stmtAccum.rows.length && String(_stmtAccum.periodId) === String(p.Id)) {
                  var allStmtT = _stmtAccum.rows.slice().sort(function (a, b) { return a.date - b.date; });
                  runReconcileRows(allStmtT, mergeStatementMeta(_stmtAccum.metas), { silent: true, onDone: function () { refreshRec(); refreshSoldCheck(); } });
                } else { refreshSoldCheck(); }
              }).catch(function (e) { console.error(e); fixTPE.disabled = false; txt(fixTPE, "⤺ Reincearca"); toast("Eroare la scoaterea flag-ului.", "error"); });
            }
