      var casaHint = ce("div", "hint"); txt(casaHint, "Banii din casă: soldul inițial + ce ai mutat din bancă (retrageri de numerar = viramente) − cheltuielile plătite cash. La închidere, numerarul numărat trebuie să fie egal cu soldul calculat aici."); casaB.appendChild(casaHint);
      var casaKv = ce("div", "jrn-kvbox"); casaB.appendChild(casaKv);
