  // test LIVE al fluxului de scan pe biblioteca unui token: urca un document de test, asteapta rezultatul in _ai_out
  function userScanTest(token, onStep) {
    var lib = _libRel(token), key = "factura__req-" + Date.now() + "-" + Math.floor(Math.random() * 1000);
    return ensureAiFolders(token).then(function () { return _testInvoicePng(); }).then(function (ab) {
      return uploadFile(lib + "/_ai", key + ".png", ab);
    }).then(function () {
      var t0 = Date.now();
      function poll(i) {
        if (i >= 19) return Promise.resolve(null);
        return new Promise(function (r) { setTimeout(r, 4000); }).then(function () {
          return fetch(_webUrl + "/_api/web/GetFileByServerRelativeUrl('" + spLit(lib + "/_ai_out/" + key + ".json") + "')/$value", { credentials: "same-origin", cache: "no-store" })
            .then(function (rr) { return rr.ok ? rr.text() : null; }, function () { return null; });
        }).then(function (tx) { if (tx) return tx; if (onStep) onStep("astept rezultatul… " + Math.round((Date.now() - t0) / 1000) + "s"); return poll(i + 1); });
      }
      return poll(0).then(function (got) {
        try { recycleFile(lib + "/_ai/" + key + ".png").catch(function () {}); } catch (e) {}
        if (got) { try { recycleFile(lib + "/_ai_out/" + key + ".json").catch(function () {}); } catch (e) {} return { ok: true, secs: Math.round((Date.now() - t0) / 1000) }; }
        return { ok: false };
      });
    });
  }
  // dialog de verificare IN APLICATIE (liste, coloane, foldere, test scan live, jurnal) pentru un token ("" = principal)
