  // creeaza listele+biblioteca pt. un token nou, copiind coloanele custom din imprestul de baza (care merge)
  function userCreate(token, onStep) {
    var sfx = "_" + token, totalCols = 0;
    function wait(ms) { return new Promise(function (r) { setTimeout(r, ms); }); }
    var chain = Promise.resolve();
    USERS_LISTS.forEach(function (pair) {
      var base = pair[0], tpl = pair[1], name = base + sfx;
      chain = chain.then(function () {
        if (onStep) onStep("Creez „" + name + "”…");
        return spGet("/_api/web/lists/getbytitle('" + spLit(name) + "')?$select=Id").then(function () { return true; }, function () { return false; })
          .then(function (exists) {
            var mk = exists ? Promise.resolve() : spPost("/_api/web/lists", { "__metadata": { "type": "SP.List" }, Title: name, BaseTemplate: tpl, ContentTypesEnabled: false });
            return mk.then(function () {
              return spGet("/_api/web/lists/getbytitle('" + spLit(base) + "')/fields?$select=SchemaXml,FromBaseType,Hidden,ReadOnlyField,CanBeDeleted&$top=500").then(function (sj) {
                var flds = (sj.d.results || []).filter(function (f) { return !f.FromBaseType && !f.Hidden && !f.ReadOnlyField && f.CanBeDeleted; });
                var c2 = Promise.resolve();
                flds.forEach(function (f) {
                  var xml = String(f.SchemaXml).replace(/\s(ID|SourceID|Version|WebId|List)="[^"]*"/g, "");
                  c2 = c2.then(function () {
                    return spPost("/_api/web/lists/getbytitle('" + spLit(name) + "')/fields/createfieldasxml",
                      { parameters: { "__metadata": { "type": "SP.XmlSchemaFieldCreationInformation" }, SchemaXml: xml, Options: 8 } })
                      .then(function () { totalCols++; }, function () {});   // coloana existenta / esuata -> ignor (idempotent)
                  }).then(function () { return wait(60); });
                });
                return c2;
              });
            });
          });
      });
    });
    return chain.then(function () { return { cols: totalCols }; });
  }
  // trimite listele unui token in cosul SharePoint (recuperabile)
  function userDelete(token) {
    var sfx = "_" + token, done = [], failed = [], chain = Promise.resolve();
    USERS_LISTS.forEach(function (pair) {
      var name = pair[0] + sfx;
      chain = chain.then(function () {
        // exista? daca NU, o consideram deja stearsa (skip, nu e eroare)
        return spGet("/_api/web/lists/getbytitle('" + spLit(name) + "')?$select=Id").then(function () {
          return spPost("/_api/web/lists/getbytitle('" + spLit(name) + "')/recycle").then(function () { done.push(name); }, function (e) { failed.push(name + " (" + ((e && e.message) || "eroare").slice(0, 50) + ")"); });
        }, function () { /* nu exista deja — ok */ });
      });
    });
    return chain.then(function () { return { done: done.length, failed: failed }; });
  }
