  // Redeschide o perioada inchisa: Status -> Deschis (poti adauga/edita iar). Folderul si datele raman.
  function reopenPeriod(p) {
    if (!p) return;
    // „Doar ultima inchisa": refuza daca exista o perioada inchisa care incepe DUPA aceasta
    // (nu poti scoate curat tranzactii dintr-o perioada inchisa ulterioara).
    var pStart = p.DataStart ? new Date(p.DataStart).getTime() : 0;
    var laterClosed = (_periods || []).filter(function (q) {
      if (String(q.Id) === String(p.Id)) return false;
      var qs = q.DataStart ? new Date(q.DataStart).getTime() : 0;
      return qs > pStart && q.Status === "Inchis";
    });
    if (laterClosed.length) {
      showDialog({
        title: "Nu pot redeschide aceasta perioada",
        message: "Se poate redeschide doar ULTIMA perioada inchisa. Exista una inchisa ulterioara („" +
          (laterClosed[0].Title || periodLabel(laterClosed[0])) + "”). Redeschide-o intai pe aceea.",
        confirmLabel: "OK"
      });
      return;
    }
    showAiLoading("Verific ce tranzactii revin in perioada…");
    findMovedBack(p).then(function (back) {
      hideAiLoading();
      var libRel = _siteRel + "/" + CONFIG.LIB.DOCS + "/";
      var inCursLabel = (p.DataStart ? isoDate(p.DataStart) : "") + "_in-curs";
      var closedLabel = periodLabel(p);
      var listNode = ce("div", "mng-list"); listNode.style.cssText = "max-height:240px;overflow:auto;margin-top:6px;";
      if (back.length) {
        var bl = document.createElement("b"); txt(bl, back.length + " tranzactie(i) revin in perioada (reportate la inchidere):"); bl.style.cssText = "display:block;font-size:12.5px;margin-bottom:6px;"; listNode.appendChild(bl);
        back.slice(0, 12).forEach(function (t) {
          var row = document.createElement("div"); row.style.cssText = "display:flex;gap:8px;justify-content:space-between;padding:5px 8px;border-bottom:1px solid var(--v-surf2, #eef2f7);font-size:12px;";
          var l = document.createElement("span"); l.style.cssText = "min-width:0;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;"; txt(l, fmtDate(t.Data, "dd.mm.yyyy") + " · " + (t.Furnizor || "(fara furnizor)")); row.appendChild(l);
          var r = document.createElement("span"); r.style.cssText = "flex:0 0 auto;font-weight:600;"; txt(r, fmtBani(Math.abs(Number(t.Suma || 0))) + " " + CONFIG.CURRENCY); row.appendChild(r);
          listNode.appendChild(row);
        });
        if (back.length > 12) { var more = ce("div", "hint"); txt(more, "… si inca " + (back.length - 12) + "."); listNode.appendChild(more); }
      } else {
        var nb = ce("div", "hint"); txt(nb, "Nicio tranzactie de readus (nu s-a reportat nimic sau a fost deja adusa)."); listNode.appendChild(nb);
      }
      showDialog({
        title: "Redeschizi perioada „" + (p.Title || closedLabel) + "”?",
        message: "Anuleaza inchiderea: tranzactiile reportate revin in perioada, data finala se elibereaza, folderul revine la „in-curs”, iar exportul inghetat se sterge. Poti edita (factura/suma), apoi inchizi din nou (se reface arhiva).",
        bodyNode: listNode,
        confirmLabel: "Redeschide", cancelLabel: "Anuleaza",
        onConfirm: function () { doReopen(p, back, libRel, inCursLabel, closedLabel); }
      });
    }).catch(function (e) {
      hideAiLoading(); console.error(e);
      showDialog({ title: "Eroare", message: "Nu am putut pregati redeschiderea: " + (e && e.message ? e.message : String(e)), confirmLabel: "OK" });
    });
  }

  // Executa redeschiderea: readuce tranzactiile, redenumeste folderul, elibereaza DataFinal, sterge inghetatul.
  function doReopen(p, back, libRel, inCursLabel, closedLabel) {
    showAiLoading("Redeschid perioada…");
    var prevFinal = p.DataFinal || null;   // data finala originala — o pastram pt. reinchidere (data blocata)
    var inCursRel = libRel + inCursLabel;
    var pStart = p.DataStart ? new Date(p.DataStart).getTime() : 0;
    var laterFolders = [];
    (_periods || []).forEach(function (q) {
      if (String(q.Id) === String(p.Id)) return;
      var qs = q.DataStart ? new Date(q.DataStart).getTime() : 0;
      if (qs >= pStart) periodLabelsFor(q).forEach(function (lb) { var rel = libRel + lb; if (laterFolders.indexOf(rel) < 0) laterFolders.push(rel); });
    });
    // 1) folderul revine la „in-curs" (ca scrierile noi sa fie consistente; periodLabelsFor acopera oricum cititul)
    renameFolder(libRel + closedLabel, inCursRel).then(function () { return ensureFolder(inCursLabel); }).then(function () {
      // 2) readu tranzactiile reportate: PerioadaId -> p, Status Draft, fara flag „din imprestul trecut", + fisierele
      return getEntityType(CONFIG.LISTS.TRX).then(function (et) {
        var chain = Promise.resolve(); var done = 0;
        back.forEach(function (t) {
          chain = chain.then(function () {
            var b = { "__metadata": { "type": et }, PerioadaId: Number(p.Id), Status: "Draft" };
            if (CONFIG.FIELDS.IMPREST_TRECUT) b[CONFIG.FIELDS.IMPREST_TRECUT] = false;
            return spPost("/_api/web/lists/getbytitle('" + CONFIG.LISTS.TRX + "')/items(" + t.Id + ")", b, { "X-HTTP-Method": "MERGE", "IF-MATCH": "*" })
              .then(function () { return moveTrxFiles(t, laterFolders, inCursRel); })
              .then(function () { done++; })
              .catch(function (e) { console.warn("reopen bring-back", t.Id, e); try { logEvent("eroare", "Redeschidere: readucere tranzactie esuata", t.Id + " " + ((e && e.message) || "")); } catch (x) {} });
          });
        });
        return chain.then(function () { return done; });
      });
    }).then(function (done) {
      // 3) perioada: titlu „in-curs", FARA data finala, Deschis
      return getEntityTypePeriods().then(function (et) {
        return spPost("/_api/web/lists/getbytitle('" + CONFIG.LISTS.PERIODS + "')/items(" + p.Id + ")",
          { "__metadata": { "type": et }, Title: inCursLabel, DataFinal: null, Status: "Deschis" }, { "X-HTTP-Method": "MERGE", "IF-MATCH": "*" });
      }).then(function () { return done; });
    }).then(function (done) {
      // 4) sterge exportul inghetat (perioada nu mai e inghetata; viitorul ZIP se reface din starea curenta)
      return recycleFile(inCursRel + "/" + FROZEN_WB_NAME)
        .catch(function () { return recycleFile(libRel + closedLabel + "/" + FROZEN_WB_NAME).catch(function () {}); })
        .then(function () { return done; });
    }).then(function (done) {
      _movedTrx = { periodId: null, items: [] };   // se reevalueaza ca perioada deschisa (fara „mutate")
      if (_activePeriod && String(_activePeriod.Id) === String(p.Id)) { _activePeriod.Status = "Deschis"; _activePeriod.DataFinal = null; _activePeriod.Title = inCursLabel; }
      // Marcheaza perioada ca „redeschisa in lucru" (partajat) -> lacatul blocheaza modificarile in alt imprest pana la reinchidere.
      if (_appCfg) { _appCfg.reopenId = Number(p.Id); _appCfg.reopenPrevFinal = prevFinal; try { saveAppConfig(_appCfg); } catch (x) {} }
      try { logEvent("actiune", "Perioada redeschisa (" + (p.Title || closedLabel) + ")", done + " tranzactii readuse"); } catch (x) {}
      return loadPeriods().then(loadTrx).then(render).then(function () {
        hideAiLoading();
        toast("Perioada redeschisa" + (done ? (" · " + done + " tranzactii readuse") : "") + ". Doar acest imprest e editabil pana il inchizi la loc.", "success");
      });
    }).catch(function (e) {
      hideAiLoading(); console.error(e);
      showDialog({ title: "Eroare la redeschidere", message: "Detalii: " + (e && e.message ? e.message : String(e)), confirmLabel: "OK" });
    });
  }

  // Converteste un Blob (sau string) in Uint8Array (consistent cu restul codului, CSP-safe).
  function blobToU8(b) {
    if (typeof b === "string") b = new Blob([b]);
    return new Promise(function (res, rej) {
      var rd = new FileReader();
      rd.onload = function () { res(new Uint8Array(rd.result)); };
      rd.onerror = function () { rej(rd.error); };
      rd.readAsArrayBuffer(b);
    });
  }

  // ZIP-ul perioadei: jurnalul Excel (mereu) + documentele din folder + extrasul de reconciliere.
  // Se descarca chiar daca folderul nu are documente, atata timp cat exista tranzactii.
  /* ---- „De confirmat": mesaj de confirmare primire + selectie documente decontate ---- */
  // Tranzactiile decontate (potrivite pe extras dupa ultimul CSV) care au document de anexat.
  function confirmItems() {
    var p = _activePeriod;
    if (!p) return null;
    var _cm = p.DataFinal ? new Date(p.DataFinal) : null; if (_cm) _cm.setHours(23, 59, 59, 999);
    var _cms = _cm ? _cm.getTime() : null;
    var out = [];
    _trx.forEach(function (t) {
      if (_cms != null && t.Data && !isNaN(new Date(t.Data).getTime()) && new Date(t.Data).getTime() > _cms) return;  // dupa data inchiderii -> nu in „de confirmat"
      if (!isCompletDoc(t)) return;                                   // are toate documentele (complet) -> de confirmat
      var ti = tipInfo(t.TipTranzactie);
      if (ti && ti.io === "Intrari") return;                          // exclud intrari/REPL
      if (Number(t.Suma || 0) <= 0) return;                           // exclud storno / zero
      if (Number(t.NrAtasamente || 0) <= 0) return;                   // fara document atasat -> nu are ce confirma
      var nr = String((CONFIG.FIELDS.NR_DOC && t[CONFIG.FIELDS.NR_DOC]) || t.NrDoc || "").trim();
      if (!nr) return;
      var hasFactura = (t.TipDocument === "Factura") || !!t.AreFactura;
      var kind = hasFactura ? "F" : (t.TipDocument === "Bon" ? "B" : "F");
      var furn = String(t.Furnizor || "").trim();
      var dataTxt = fmtDate(t.Data, "dd.mm.yyyy");
      out.push({ t: t, kind: kind, furnizor: furn, nr: nr, data: dataTxt,
        line: furn + " – " + (kind === "B" ? "B." : "F.") + " " + nr + " / " + dataTxt });
    });
    return out;
  }

  // Mesajul .txt de confirmare, pe sectiuni (Facturi „F." / Bonuri „B.").
  function buildConfirmText(items) {
    var byFurn = function (a, b) {
      var fa = (a.furnizor || "").toLowerCase(), fb = (b.furnizor || "").toLowerCase();
      if (fa < fb) return -1; if (fa > fb) return 1; return (a.data || "").localeCompare(b.data || "");
    };
    var fac = items.filter(function (x) { return x.kind !== "B"; }).sort(byFurn);
    var bon = items.filter(function (x) { return x.kind === "B"; }).sort(byFurn);
    var SEP = "________________________________";
    var EN = (_lang === "en");   // [b115] mesajul „de confirmat” in EN cand limba e engleza
    var L = [];
    if (EN) {
      L.push("Hello,"); L.push("");
      L.push("Please confirm receipt of the goods related to the documents attached to this message."); L.push("");
      L.push("The attached documents are the following:"); L.push(SEP);
      if (fac.length) { L.push(""); L.push("Invoices:"); fac.forEach(function (x, i) { L.push((i + 1) + ". " + x.line); }); L.push(SEP); }
      if (bon.length) { L.push(""); L.push("Fiscal receipts / other documents:"); bon.forEach(function (x, i) { L.push((i + 1) + ". " + x.line); }); }
      L.push(""); L.push("Thank you!");
    } else {
      L.push("Salut,"); L.push("");
      L.push("Te rog să-mi confirmi primirea produselor aferente documentelor anexate la acest mesaj."); L.push("");
      L.push("Documentele anexate sunt următoarele:"); L.push(SEP);
      if (fac.length) { L.push(""); L.push("Facturi:"); fac.forEach(function (x, i) { L.push((i + 1) + ". " + x.line); }); L.push(SEP); }
      if (bon.length) { L.push(""); L.push("Bonuri fiscale / alte documente:"); bon.forEach(function (x, i) { L.push((i + 1) + ". " + x.line); }); }
      L.push(""); L.push("Mulțumesc!");
    }
    return L.join("\n");
  }

  // Fisierele (din lista deja descarcata in ZIP) care apartin unei tranzactii — aceeasi logica de potrivire ca in vizualizatorul de documente.
  function filesForTrx(t, files) {
    var furn = slug(t.Furnizor || "").toLowerCase();
    var nrd = slug((CONFIG.FIELDS.NR_DOC && t[CONFIG.FIELDS.NR_DOC]) || t.NrDoc || "").toLowerCase();
    var recNames = (CONFIG.FIELDS.FILES_NAMES && t[CONFIG.FIELDS.FILES_NAMES]) ? String(t[CONFIG.FIELDS.FILES_NAMES]).split("\n").map(function (s) { return s.trim().toLowerCase(); }).filter(Boolean) : [];
    var aprUrlF = (CONFIG.FIELDS.APPROVAL_DOC && t[CONFIG.FIELDS.APPROVAL_DOC]) || "";
    var aprName = aprUrlF ? decodeURIComponent(String(aprUrlF).split("/").pop()).toLowerCase() : "";
    var hasAtt = (t.NrAtasamente || 0) > 0;
    return files.filter(function (fl) {
      var nm = String(fl.name || fl.Name || "").toLowerCase();
      if (aprName && nm === aprName) return true;
      if (recNames.length) return recNames.indexOf(nm) >= 0;
      if (!hasAtt) return false;
      if (furn && nrd && nm.indexOf(furn) === 0 && nm.indexOf(nrd) >= 0) return true;
      if (nrd && nrd.length > 1 && nm.indexOf(nrd) >= 0) return true;
      return false;
    });
  }

  // True daca numele respecta tiparul documentelor de tranzactie (furnizor_tip_nr_data...).
  // Doar fisierele de tip document pot fi considerate „orfane" si mutate in cos; restul le lasam neatinse.
  function isDocName(nm) {
    return /_chitanta-pentru-|_chitanta_|_factura-spv_|_factura_|_aviz-pentru-|_aviz_|_bon_/.test(String(nm || "").toLowerCase());
  }
  // Incarca tranzactiile unei perioade anume (pt. ZIP, ca sa stim ce fisiere mai sunt „revendicate").
  // Intoarce null daca incarcarea esueaza -> in acest caz NU curatam nimic (siguranta).
  function trxForZip(p) {
    return spGet("/_api/web/lists/getbytitle('" + CONFIG.LISTS.TRX + "')/items?$filter=PerioadaId eq " + p.Id + "&$top=2000")
      .then(function (j) { return (j.d && j.d.results) || []; })
      .catch(function () { return null; });
  }

  // Documente care NU intra in arhiva ZIP a perioadei (dar NU se sterg — merg in imprestul urmator):
  // tranzactii in curs de clarificare, si cele marcate „de raportat".
  // [b118] FIX: stornourile au document propriu si APAR in Excel (fila Tranzactii) -> trebuie sa fie SI in arhiva.
  //   Inainte erau excluse aici (suma < 0), deci documentul aparea in jurnal dar lipsea din ZIP la inchidere/descarcare.
  function zipExclude(t) {
    if (!t) return false;
    if (isReportat(t)) return true;                           // marcat de raportat -> merge mai departe
    if (Number(t.Suma || 0) < 0) return false;               // storno / corectie -> document inclus in arhiva (apare si in Excel)
    var st = trxStage(t);
    if (st === "clarif" || st === "clarif-spv") return true;  // in curs de clarificare
    return false;
  }

  // [b88] Export: la perioada DESCHISA, intreaba data de final (sugerata din extras) inainte de a face ZIP-ul.
  //   Numele arhivei iese cu acea data (nu „in-curs”) si jurnalul e taiat la ea. Perioada inchisa -> export direct.
  function zipPeriodPrompt(p) {
    if (!p) return;
    if (p.Status === "Inchis") { zipPeriod(p); return; }
    var stmtDate = (_lastStmtMeta && String(_lastStmtMeta.periodId) === String(p.Id) && _lastStmtMeta.dataFinal) ? isoDate(_lastStmtMeta.dataFinal) : null;
    var pre = stmtDate || (p.DataFinal ? isoDate(p.DataFinal) : isoDate(new Date()));
    var wrap = ce("div", "dlg-wrap"); var dlg = ce("div", "dlg"); dlg.style.maxWidth = "460px";
    function close() { if (wrap.parentNode) wrap.parentNode.removeChild(wrap); }
    var h = document.createElement("div"); h.className = "h"; txt(h, "Export — data de final"); dlg.appendChild(h);
    var bd = document.createElement("div"); bd.className = "b"; dlg.appendChild(bd);
    var info = ce("div", "hint"); txt(info, "Perioada nu e închisă. Alege data de final pentru acest export. Se descarcă DOAR pentru această perioadă: jurnalul Excel, documentele, folderul „de confirmat” și mesajul de confirmare — toate tăiate la data aleasă. Numele arhivei iese cu această dată."); bd.appendChild(info);
    var fld = ce("div", "field"); var lab = document.createElement("label"); txt(lab, "Data de final"); fld.appendChild(lab);
    var dEnd = input("date", pre); fld.appendChild(dEnd); bd.appendChild(fld);
    var warn = ce("div", "hint"); warn.style.cssText = "margin-top:4px;font-size:11.5px;"; bd.appendChild(warn);
    function refreshWarn() {
      if (stmtDate && dEnd.value && dEnd.value !== stmtDate) { warn.style.color = "var(--v-ambtx,#b45309)"; txt(warn, "⚠ Data aleasa difera de data ultimului extras (" + fmtDate(stmtDate, "dd.mm.yyyy") + ")."); }
      else if (stmtDate) { warn.style.color = "var(--v-grntx,#1d6b58)"; txt(warn, "Pre-completata cu data ultimului extras. O poti schimba."); }
      else { warn.style.color = "var(--v-ambtx,#b45309)"; txt(warn, "Nu e extras incarcat — verifica data."); }
    }
    dEnd.addEventListener("change", refreshWarn); refreshWarn();
    var f = document.createElement("div"); f.className = "f";
    var cancel = ce("button", "btn ghost"); txt(cancel, "Anuleaza"); cancel.addEventListener("click", close); f.appendChild(cancel);
    var ok = ce("button", "btn accent"); txt(ok, "⬇ Descarca ZIP"); ok.addEventListener("click", function () {
      if (!dEnd.value) { toast("Alege data de final.", "error"); return; }
      var ed = dEnd.value; close(); zipPeriod(p, { endDate: ed });
    });
    f.appendChild(ok); dlg.appendChild(f);
    wrap.addEventListener("click", function (e) { if (e.target === wrap) close(); });
    wrap.appendChild(dlg); el(APP_ID + "-app").appendChild(wrap);
  }
  /* ===========================================================================
     [b150] JURNAL OFICIAL BETEL — umplere chirurgicala 1:1 a template-ului .xlsx
     -------------------------------------------------------------------------
     Foloseste JSZip (din SiteAssets/XLSM Library). Editeaza DOAR celulele de date
     din '1-Transactions' (col. D..L randuri 12+, plus sectiunile Transferuri /
     Avansuri / Alocatii) si celulele de perioada (K4/N4/N5). Pune fullCalcOnLoad
     ca Excel sa recalculeze toate formulele + reconcilierea la deschidere.
     NU atinge formule, desene, form controls, validari sau imagini -> fidelitate
     byte-cu-byte pe tot restul fisierului. Masterul per-persoana NU se suprascrie:
       ImprestDocumente[_profil]/Journal Banca&Casa - <depozitar>/...<depozitar>.xlsx
     iar la export se produce o copie DATATA inclusa in ZIP (+ urcata in folderul
     perioadei, best-effort).
     =========================================================================== */
  var _JSZIP_REL = "/SiteAssets/XLSM Library/jszip.min.js";
  var _jszipLoad = null;
  function loadJSZip() {
    if (typeof window !== "undefined" && window.JSZip) return Promise.resolve(window.JSZip);
    if (_jszipLoad) return _jszipLoad;
    _jszipLoad = new Promise(function (resolve, reject) {
      // Paginile SharePoint au un loader AMD (define.amd). JSZip e UMD: daca vede define.amd se
      // inregistreaza ca modul AMD si NU seteaza window.JSZip ("incarcat dar absent"). Dezactivam
      // temporar define/module/exports cat dureaza incarcarea -> JSZip cade pe ramura globala si
      // seteaza window.JSZip. Restauram imediat (onload ruleaza DUPA executia scriptului).
      var hadDef = ("define" in window), hadMod = ("module" in window), hadExp = ("exports" in window);
      var _def = window.define, _mod = window.module, _exp = window.exports;
      function restore() { try { if (hadDef) window.define = _def; if (hadMod) window.module = _mod; if (hadExp) window.exports = _exp; } catch (e) {} }
      try { if (hadDef) window.define = undefined; if (hadMod) window.module = undefined; if (hadExp) window.exports = undefined; } catch (e) {}
      var s = document.createElement("script");
      s.src = _webUrl + _JSZIP_REL; s.async = true;
      s.onload = function () {
        restore();
        if (typeof window !== "undefined" && window.JSZip) resolve(window.JSZip);
        else { _jszipLoad = null; reject(new Error("JSZip incarcat dar nu a expus window.JSZip")); }
      };
      s.onerror = function () { restore(); _jszipLoad = null; reject(new Error("Nu am putut incarca JSZip din assets (verifica /SiteAssets/XLSM Library/jszip.min.js)")); };
      document.head.appendChild(s);
    });
    return _jszipLoad;
  }

  // Serial Excel (sistem 1900) — zile de la 1899-12-30; null daca data e invalida.
  function _xlSerial(d) {
    d = new Date(d); if (isNaN(d.getTime())) return null;
    return Math.round((Date.UTC(d.getFullYear(), d.getMonth(), d.getDate()) - Date.UTC(1899, 11, 30)) / 86400000);
  }
  function _xlEsc(s) { return String(s == null ? "" : s).replace(/&/g, "&amp;").replace(/</g, "&lt;").replace(/>/g, "&gt;"); }
  function _xlNum(v) { v = Number(v); if (!isFinite(v)) v = 0; return String(v); }
  // Seteaza valoarea unei celule in XML-ul foii, PASTRAND stilul (atributul s=).
  //   isText=true -> inlineStr (sigur pt. validari/formule). keepFormula=true -> nu
  //   suprascrie o celula care are deja o formula (<f) (ex. destinatia auto la transferuri).
  function _xlSet(xml, ref, value, isText, keepFormula) {
    var re = new RegExp("<c r=\"" + ref + "\"((?:\\s+[a-zA-Z0-9:]+=\"[^\"]*\")*)\\s*(/>|>[\\s\\S]*?</c>)");
    var m = re.exec(xml);
    if (!m) return xml;                                   // celula inexistenta -> best-effort, ignora
    if (keepFormula && m[2].indexOf("<f") >= 0) return xml;
    var sm = /\ss="(\d+)"/.exec(m[1]);
    var st = sm ? (" s=\"" + sm[1] + "\"") : "";
    var cell = isText
      ? ("<c r=\"" + ref + "\"" + st + " t=\"inlineStr\"><is><t xml:space=\"preserve\">" + _xlEsc(value) + "</t></is></c>")
      : ("<c r=\"" + ref + "\"" + st + "><v>" + _xlNum(value) + "</v></c>");
    return xml.slice(0, m.index) + cell + xml.slice(m.index + m[0].length);
  }
  // Goleste o celula (pastrand stilul) — pt. randuri ramase din master care nu mai au date in perioada curenta.
  function _xlClear(xml, ref) {
    var re = new RegExp("<c r=\"" + ref + "\"((?:\\s+[a-zA-Z0-9:]+=\"[^\"]*\")*)\\s*(/>|>[\\s\\S]*?</c>)");
    var m = re.exec(xml);
    if (!m) return xml;
    if (m[2].indexOf("<f") >= 0) return xml;                // nu sterge formule
    var sm = /\ss="(\d+)"/.exec(m[1]); var st = sm ? (" s=\"" + sm[1] + "\"") : "";
    return xml.slice(0, m.index) + "<c r=\"" + ref + "\"" + st + "/>" + xml.slice(m.index + m[0].length);
  }

  // Imparte tranzactiile pe sectiunile jurnalului oficial (deschiderile sunt auto in template).
  function _routeJournalTrx(rows) {
    var out = { main: [], transfers: [], advances: [], allowances: [] };
    (rows || []).forEach(function (t) {
      var tip = String(t.TipTranzactie || "");
      if (tip === "OBLB" || tip === "OBLC") return;        // solduri initiale -> calculate de template
      if (isViramentCasa(t)) { out.transfers.push(t); return; }
      if (isAvansNumerar(t)) { out.advances.push(t); return; }
      if (tip === "ALLOW") { out.allowances.push(t); return; }
      // [b156] Grila = exact ca vechiul .xls (inJurnalRow): income / storno / complet (cu document);
      //   exclude reportatele (mutate la imprestul urmator) si cele fara document valid.
      //   Tranzactiile „din imprestul trecut" CU document INTRA in grila — plata lor e pe extrasul curent
      //   (data facturii poate fi inainte de start, dar banca le-a decontat in perioada).
      //   Exceptie: cele in clarificare apar DOAR in „in curs de clarificare", nu si in grila (evita dubla numarare).
      if (inJurnalRow(t) || (isBlocatExtras(t) && hasJustif(t) && isBankTrx(t))) out.main.push(t);   // [b158] inJurnalRow exclude cheltuielile fara document; [b171] EXCEPTIE: blocat pe extras CU document -> in grila (cheltuiala reala pending). Fara document ramane in afara grilei (doar la „nu apar pe extras" + „in curs de clarificare"). Add-back-ul din „nu apar pe extras" anuleaza -suma din grila -> Diferenta 0.
    });
    return out;
  }

  // [b153] Normalizare TIP pentru Excel: valorile stocate pot fi neuniforme („COD - descriere", cod-eticheta,
  //   gol). Le aducem la codul curat din droplista Excel (References!C17:C73). Ce nu se poate mapa ramane
  //   neschimbat (apare rosu in Excel -> il alegi din droplista in app). Harta _tipOverride e pt. valorile care
  //   NU contin codul direct (cod intern / prescurtare) — EDITABILA, confirmata cu utilizatorul.
  var _tipOverride = {
    "99002-consumabile": "IC26",                   // [b161] 99002 = contul IC -> IC26 (ca in jurnalele model)
    "205": "CONSUMABILE-205"                        // centru de cost 205 -> consumabile 205 (de confirmat)
  };
  // [b161] Reclasificare pe cod VALID: in jurnalele model „ALTE CONSUMABILE-*" NU apar — cumparaturile pe
  //   contul 99002 se raporteaza ca IC26 (Congres International). Se aplica INAINTE de tipInfo (altfel codul
  //   valid ar fi pastrat ca atare). Daca vrei alt mapping pe 99002, editezi aici.
  var _tipForce = {
    "ALTE CONSUMABILE-MNT": "IC26",
    "ALTE CONSUMABILE-BUCATARIE": "IC26"
  };
  function _tipExcel(tip) {
    var t = String(tip == null ? "" : tip).trim();
    if (!t) return "";
    if (Object.prototype.hasOwnProperty.call(_tipForce, t)) return _tipForce[t];   // [b161] 99002 -> IC26 (model)
    if (tipInfo(t)) return t;                                  // deja cod valid
    var i = t.indexOf(" - ");                                  // „COD - descriere" -> COD
    if (i > 0) { var c = t.slice(0, i).trim(); if (tipInfo(c)) return c; }
    if (Object.prototype.hasOwnProperty.call(_tipOverride, t)) return _tipOverride[t];
    return t;                                                   // necunoscut -> ramane (rosu in Excel)
  }

  // [b172] Nr. ref. la EXPORT: NrRef salvat pe tranzactie SAU, daca e gol (tranzactie salvata cand bugetul
  //   n-avea Cod / lista de bugete nu era inca incarcata), se re-deduce ACUM din bugetul tranzactiei
  //   (bug.Cod sau prefixul numeric din titlul bugetului) — DOAR pentru codurile de proiect (pdim).
  //   Asa, Dipol/ADAL pe 20G0000 nu mai ies cu col. G goala in jurnalul oficial.
  function _nrRefX(t) {
    if (!t) return "";
    if (t.NrRef) return t.NrRef;
    var tipX = _tipExcel(t.TipTranzactie);
    var ti = tipInfo(tipX);
    if (!ti || !ti.pdim) return "";                             // doar codurile de proiect poarta numar de referinta
    var bg = (CONFIG.FIELDS.BUGET && t[CONFIG.FIELDS.BUGET]) || "";
    return bg ? (refProiect(tipX, bg, null) || "") : "";
  }

  // Clasificare pentru reconciliere (folosind flag-urile reale ale appului, ca la pasul „Verificare sold"):
  //   blocate = marcate manual „Sume blocate pe extras" (isBlocatExtras) -> „nu apar pe extras bancar";
  //   clarif  = fara document valid / in clarificare -> „in curs de clarificare".
  function _carryFromTrx(rows) {
    var out = { blocate: [], clarif: [] };
    (rows || []).forEach(function (t) {
      var ti = tipInfo(t.TipTranzactie);
      if (ti && ti.io === "Intrari") return;                 // intrarile nu se reporteaza
      if (isViramentCasa(t)) return;                          // viramentul = transfer
      if (Number(t.Suma || 0) < 0) return;                   // storno/corectie
      if (isImprestTrecut(t)) return;                         // din imprestul trecut -> tratat separat
      if (isBlocatExtras(t)) { out.blocate.push(t); if (!hasJustif(t)) out.clarif.push(t); return; } // [b171] blocat pe extras -> „nu apar pe extras"; fara document -> SI „in curs de clarificare" (net 0). Consecvent cu _reconFromMatched.
      if (!hasJustif(t) || inClarif(t)) { out.clarif.push(t); return; }  // fara document -> in curs de clarificare
    });
    return out;
  }
  // [b157] Reconciliere bazata pe potrivirea REALA cu extrasul (matchedIds din pasul „Verificare sold"),
  //   ca jurnalul oficial sa se inchida automat (oglindeste reconcilierea din aplicatie):
  //   - „nu apar pe extras bancar" = cheltuieli bancare cu document (in grila) care NU s-au potrivit pe extras
  //     (inregistrate, dar inca nedecontate) -> se ADUNA inapoi;
  //   - „in curs de clarificare" = cheltuieli bancare FARA document care S-AU potrivit pe extras
  //     (decontate pe banca, dar fara act) -> se SCAD.
  //   Cele fara document SI nepotrivite raman pe perioada urmatoare (fara ajustare). Identitatea se inchide:
  //     sold_final + nu_apar - clarificare = sold_initial + intrari - (cheltuieli decontate) = sold extras.
  function _reconFromMatched(rows, matched) {
    var out = { blocate: [], clarif: [] };
    (rows || []).forEach(function (t) {
      if (!isBankTrx(t)) return;                              // doar tranzactii bancare
      var ti = tipInfo(t.TipTranzactie);
      if (ti && ti.io === "Intrari") return;                 // intrarile (REPL) nu se reconciliaza aici
      if (isViramentCasa(t)) return;                         // viramentul = transfer
      if (Number(t.Suma || 0) < 0) return;                   // storno/corectie
      if (isReportat(t)) return;                             // mutate la imprestul urmator (nu sunt in grila nici aici)
      if (isImprestTrecut(t)) return;                        // [b158] din imprestul trecut -> raman in GRILA (transactions), nu in „nu apar pe extras"
      var isMatched = !!matched[String(t.Id)];
      if (isBlocatExtras(t)) {                                 // [b171] blocat pe extras (pending). NU e niciodata in grila fara document (trxStage="blocate").
        var blocDoc = hasJustif(t);
        if (!isMatched) {                                     // inca nedecontat pe extras
          out.blocate.push(t);                               // -> „nu apar pe extras" (nu apare pe extrasul postat)
          if (!blocDoc) out.clarif.push(t);                  // fara document -> SI „in curs de clarificare" (net 0 cu add-back-ul; NU intra in grila). Cu document -> e in grila, doar nu apar pe extras.
        } else if (!blocDoc) {                                // s-a decontat intre timp, dar fara document
          out.clarif.push(t);                                // -> „in curs de clarificare" (banca l-a scazut, noi n-avem act)
        }                                                     // decontat + cu document -> deja in grila, nicio ajustare
        return;
      }
      var inGrid = isCompletDoc(t) && !inClarif(t);          // are document valid -> apare in grila
      if (inGrid) { if (!isMatched) out.blocate.push(t); }   // in grila, dar NU pe extras -> nu apar pe extras
      else { if (isMatched) out.clarif.push(t); }            // fara document, dar pe extras -> in curs de clarificare
    });
    return out;
  }
  // Jurnalul oficial are MAXIM 6 randuri pe sectiune. <=6 -> cate un rand; >6 -> primele 5 + rand 6 CUMULAT
  //   (data celei de-a 6-a, suma 6..N, descriere „cumulat N: nume1 + nume2 + …") — exact ca vechiul Excel.
  function _recon6(sorted) {
    var mk = function (t) { return { date: t.Data, ref: (fisiereAsociate(t) || t.Furnizor || ("#" + t.Id)), amount: Number(t.Suma || 0) }; };
    if (sorted.length <= 6) return sorted.map(mk);
    var first = sorted.slice(0, 5).map(mk);
    var rest = sorted.slice(5), sum = 0, names = [];
    rest.forEach(function (t) { sum += Number(t.Suma || 0); names.push(t.Furnizor || ("#" + t.Id)); });
    first.push({ date: rest[0].Data, ref: ("cumulat " + rest.length + ": " + names.join(" + ")), amount: Number(sum.toFixed(2)) });
    return first;
  }
  // Completeaza o sectiune de 6 randuri din foaia de reconciliere (G=data, H=nr.ref/descriere, I=suma); goleste restul.
  function _fillReconSection(xml, startRow, items) {
    for (var i = 0; i < 6; i++) {
      var rr = startRow + i, it = items[i];
      if (it) {
        var ds = _xlSerial(it.date);
        xml = (ds != null) ? _xlSet(xml, "G" + rr, ds, false) : _xlClear(xml, "G" + rr);
        xml = _xlSet(xml, "H" + rr, it.ref || "", true);
        xml = _xlSet(xml, "I" + rr, Number(it.amount || 0), false);
      } else {
        xml = _xlClear(xml, "G" + rr); xml = _xlClear(xml, "H" + rr); xml = _xlClear(xml, "I" + rr);
      }
    }
    return xml;
  }

  // Eticheta interval in romana: "10-13 Iunie 2026" / "30 Iunie - 3 Iulie 2026".
  function _roDateRange(start, end) {
    var M = ["Ianuarie", "Februarie", "Martie", "Aprilie", "Mai", "Iunie", "Iulie", "August", "Septembrie", "Octombrie", "Noiembrie", "Decembrie"];
    var s = new Date(start), e = new Date(end);
    if (isNaN(s.getTime())) s = e; if (isNaN(e.getTime())) e = s;
    if (isNaN(s.getTime())) return isoDate(new Date());
    var sd = s.getDate(), ed = e.getDate(), sm = s.getMonth(), em = e.getMonth(), sy = s.getFullYear(), ey = e.getFullYear();
    if (sy === ey && sm === em) return sd + "-" + ed + " " + M[sm] + " " + sy;
    if (sy === ey) return sd + " " + M[sm] + " - " + ed + " " + M[em] + " " + sy;
    return sd + " " + M[sm] + " " + sy + " - " + ed + " " + M[em] + " " + ey;
  }

  // [b159] Personalizeaza foaia „References" a jurnalului oficial cu datele depozitarului curent (din CONFIG.FUND),
  //   ca ACELASI template generic sa mearga pentru ORICE depozitar. Fara asta, SUMIF-urile de reconciliere
  //   (care cheama numele contului prin BankAccountName/CashAccountName) nu prind tranzactiile altui depozitar.
  //   Celulele: References!I6=cont bancar, I8=cont casa, D6=departament, D8=plafon imprest. -> Promise.
  function _writeReferences(zip) {
    var fW = zip.file("xl/workbook.xml"), fRels = zip.file("xl/_rels/workbook.xml.rels");
    if (!fW || !fRels) return Promise.resolve();
    return Promise.all([fW.async("string"), fRels.async("string")]).then(function (a) {
      var wx = a[0], rels = a[1];
      var sm = /<sheet [^>]*name="References"[^>]*\/>/.exec(wx);   // elementul foii „References"
      if (!sm) return;
      var rm = /r:id="([^"]+)"/.exec(sm[0]); if (!rm) return;
      var tm = new RegExp('Id="' + rm[1] + '"[^>]*Target="([^"]+)"').exec(rels); if (!tm) return;
      var path = "xl/" + String(tm[1]).replace(/^\/?(xl\/)?/, "");   // ex: xl/worksheets/sheet8.xml
      var fRef = zip.file(path); if (!fRef) return;
      return fRef.async("string").then(function (refXml) {
        var dept = String(CONFIG.FUND.nume || "").trim();
        var plafon = (_appCfg && isFinite(Number(_appCfg.imprestPlafon)) && Number(_appCfg.imprestPlafon) > 0)
          ? Number(_appCfg.imprestPlafon) : Number(CONFIG.FUND.fonduriAprobate || 50000);
        if (CONFIG.FUND.contBancar) refXml = _xlSet(refXml, "I6", CONFIG.FUND.contBancar, true);   // BankAccountName
        if (CONFIG.FUND.casa) refXml = _xlSet(refXml, "I8", CONFIG.FUND.casa, true);               // CashAccountName
        if (dept) refXml = _xlSet(refXml, "D6", dept, true);                                       // Department
        refXml = _xlSet(refXml, "D8", plafon, false);                                              // ApprovedAmount
        zip.file(path, refXml);
      });
    });
  }

  // Construieste binarul jurnalului oficial completat. -> Promise<{name, bytes}>
  //   periodTrx = tranzactiile perioadei (din trxForZip). opts.endDate/lastStmtDate optionale.
  function buildOfficialJournal(p, periodTrx, opts) {
    opts = opts || {};
    var depoz = String(CONFIG.FUND.depozitar || "").trim();
    var baseName = "Journal Banca&Casa - " + depoz;
    var masterRel = "/" + CONFIG.LIB.DOCS + "/" + baseName + "/" + baseName + ".xlsx";
    var endD = opts.endDate ? new Date(opts.endDate) : (p.DataFinal ? new Date(p.DataFinal) : new Date());
    var outName = baseName + " " + _roDateRange(p.DataStart, endD) + ".xlsx";
    // Taiere pe data (ca la .xls): intrarile raman mereu; ce e clar dupa data de final se exclude.
    var cut = opts.endDate ? new Date(opts.endDate) : (p.DataFinal ? new Date(p.DataFinal) : null);
    if (cut) cut.setHours(23, 59, 59, 999);
    function inCut(t) {
      if (!cut) return true;
      var ti = tipInfo(t.TipTranzactie); if (ti && ti.io === "Intrari") return true;
      if (!t.Data) return true; var tm = new Date(t.Data).getTime();
      if (isNaN(tm)) return true; return tm <= cut.getTime();
    }

    return loadJSZip().then(function (JSZip) {
      return spGetBuffer(masterRel).catch(function () {
        throw new Error("Template-ul jurnalului oficial lipseste: " + masterRel + " - pune fisierul BETEL generic acolo (folder '" + baseName + "' cu fisierul '" + baseName + ".xlsx'). Verifica si depozitarul in Setari > Configurare aplicatie (acum: '" + (depoz || "necompletat") + "').");
      }).then(function (ab) { return JSZip.loadAsync(ab); }).then(function (zip) {
        return _writeReferences(zip).then(function () {   // [b159] personalizeaza conturile depozitarului in References
        var fS = zip.file("xl/worksheets/sheet3.xml"), fW = zip.file("xl/workbook.xml"), fR = zip.file("xl/worksheets/sheet4.xml");
        if (!fS || !fW) throw new Error("Template incomplet (sheet3/workbook lipsa)");
        return Promise.all([fS.async("string"), fW.async("string"), (fR ? fR.async("string") : Promise.resolve(null))]).then(function (arr) {
          var sx = arr[0], wx = arr[1], rx = arr[2];
          var ordered = (periodTrx || []).filter(inCut).slice().sort(function (a, b) {
            var da = new Date(a.Data).getTime() || 0, db = new Date(b.Data).getTime() || 0;
            return (da - db) || ((a.NrCrt || 0) - (b.NrCrt || 0));
          });
          var R = _routeJournalTrx(ordered);
          var r, ds;
          // GRILA PRINCIPALA: randuri 12..261, col. D..L (C=nr.crt, M..Q=formule template).
          r = 12; R.main.forEach(function (t) {
            if (r > 261) return; ds = _xlSerial(t.Data);
            sx = _xlSet(sx, "D" + r, t.MetodaPlata || "", true);
            if (ds != null) sx = _xlSet(sx, "E" + r, ds, false);
            var _tipX = _tipExcel(t.TipTranzactie);
            sx = _xlSet(sx, "F" + r, _tipX, true);
            // [b160] Nr. ref. (col. G) DOAR pentru coduri de proiect (pdim): 10S/15S/20G/38x/40x -> numar requisition (ex. 1425).
            //   Codurile pe cont contabil (IC26, ALTE CONSUMABILE-*, CONSUMABILE-*, REPL, CHELT.*, ALIMENTE-*...) NU au Nr. ref.
            //   Fara filtrul asta, prefixul de cont din titlul bugetului ("99002 — IC26-General" -> "99002") se scurgea in Nr. ref.
            var _tiX = tipInfo(_tipX);
            var _refX = _nrRefX(t);   // [b172] NrRef salvat SAU re-dedus din bugetul tranzactiei (fallback)
            if (_refX && _tiX && _tiX.pdim) sx = _xlSet(sx, "G" + r, _refX, true);
            else sx = _xlClear(sx, "G" + r);
            sx = _xlSet(sx, "H" + r, descriereExport(t), true);
            if (t.CodFurnizor) sx = _xlSet(sx, "I" + r, t.CodFurnizor, true);
            sx = _xlSet(sx, "J" + r, Number(t.Suma || 0), false);
            sx = _xlSet(sx, "K" + r, Number(t.Cantitate || 1), false);
            sx = _xlSet(sx, "L" + r, t.UOM || "ea", true);
            r++;
          });
          // TRANSFERURI: 384..435 (D=data, E=suma, F=sursa=banca; G=destinatie auto/literal).
          r = 384; R.transfers.forEach(function (t) {
            if (r > 435) return; ds = _xlSerial(t.Data);
            if (ds != null) sx = _xlSet(sx, "D" + r, ds, false);
            sx = _xlSet(sx, "E" + r, Number(t.Suma || 0), false);
            sx = _xlSet(sx, "F" + r, CONFIG.FUND.contBancar, true);
            sx = _xlSet(sx, "G" + r, CONFIG.FUND.casa, true, true);
            r++;
          });
          // AVANSURI: 267..318 (D=data emitere, E=destinatar, G=suma).
          r = 267; R.advances.forEach(function (t) {
            if (r > 318) return; ds = _xlSerial(t.Data);
            if (ds != null) sx = _xlSet(sx, "D" + r, ds, false);
            sx = _xlSet(sx, "E" + r, t.Furnizor || "", true);
            sx = _xlSet(sx, "G" + r, Number(t.Suma || 0), false);
            r++;
          });
          // ALOCATII (S-24): 326..377 (D=data, E=persoana, G=suma).
          r = 326; R.allowances.forEach(function (t) {
            if (r > 377) return; ds = _xlSerial(t.Data);
            if (ds != null) sx = _xlSet(sx, "D" + r, ds, false);
            sx = _xlSet(sx, "E" + r, t.Furnizor || "", true);
            sx = _xlSet(sx, "G" + r, Number(t.Suma || 0), false);
            r++;
          });
          // SOLD INITIAL: OBLC=rand 9 (casa), OBLB=rand 10 (banca). Reconcilierea citeste N9/N10 (E7/I7).
          //   Punem suma in J (cosmetic) si in N (efectul citit de reconciliere; pastram formula daca exista).
          var _sCasa = periodSoldCasa(p), _sBanca = periodSoldBanca(p);
          sx = _xlSet(sx, "J9", _sCasa, false);  sx = _xlSet(sx, "N9", _sCasa, false, true);
          sx = _xlSet(sx, "J10", _sBanca, false); sx = _xlSet(sx, "N10", _sBanca, false, true);
          // PERIOADA: K4=start, N4=final, N5=data ultimului extras.
          var sStart = _xlSerial(p.DataStart), sEnd = _xlSerial(endD);
          if (sStart != null) sx = _xlSet(sx, "K4", sStart, false);
          if (sEnd != null) sx = _xlSet(sx, "N4", sEnd, false);
          var sStmt = opts.lastStmtDate ? _xlSerial(opts.lastStmtDate) : sEnd;
          if (sStmt != null) sx = _xlSet(sx, "N5", sStmt, false);
          // RECONCILIERE (foaia 2-Reconciliation): listele „nu apar pe extras" (22-27) si „in curs de
          //   clarificare" (30-35), max 6 randuri cu agregare ca vechiul Excel; + soldul de pe extras (I20).
          //   Totalurile (I28/I36) si restul reconcilierii sunt formule ale template-ului.
          if (rx) {
            // [b157] Daca avem reconcilierea cu extrasul (matchedIds din „Verificare sold"), o oglindim 1:1
            //   (jurnalul se inchide automat). Altfel (fara extras incarcat) revenim la clasificarea pe flag-uri.
            var _lrM = (_lastReconcile && p && String(_lastReconcile.periodId) === String(p.Id) && _lastReconcile.matchedIds) ? _lastReconcile : null;
            var cfR;
            if (_lrM) {
              var _mm = {}; _lrM.matchedIds.forEach(function (id) { _mm[String(id)] = 1; });
              cfR = _reconFromMatched(ordered, _mm);
            } else {
              cfR = _carryFromTrx(ordered);
            }
            var byNr = function (a, b) { return (a.NrCrt || 0) - (b.NrCrt || 0); };
            rx = _fillReconSection(rx, 22, _recon6(cfR.blocate.slice().sort(byNr)));   // nu apar pe extras bancar
            rx = _fillReconSection(rx, 30, _recon6(cfR.clarif.slice().sort(byNr)));    // in curs de clarificare
            if (opts.stmtBalance != null && isFinite(opts.stmtBalance)) rx = _xlSet(rx, "I20", Number(opts.stmtBalance), false);
          }
          // Recalc fortat la deschidere (toate formulele + reconcilierea + soldurile).
          wx = wx.replace(/<calcPr ([^>]*?)\/>/, function (full, attrs) {
            return /fullCalcOnLoad=/.test(attrs) ? full : ("<calcPr " + attrs + " fullCalcOnLoad=\"1\"/>");
          });
          // [b161] Deschide jurnalul pe „1-Transactions" (ca jurnalele model), nu pe „Decont".
          //   activeTab = pozitia 0-based a foii dupa ordinea <sheet> din workbook.xml; masterul era salvat pe Decont.
          (function () {
            var order = [], re = /<sheet [^>]*name="([^"]+)"/g, mm;
            while ((mm = re.exec(wx))) order.push(mm[1]);
            var idx = order.indexOf("1-Transactions"); if (idx < 0) idx = 0;
            if (/<workbookView\b[^>]*\bactiveTab="\d+"/.test(wx))
              wx = wx.replace(/(<workbookView\b[^>]*\bactiveTab=")\d+(")/, "$1" + idx + "$2");
            else
              wx = wx.replace(/<workbookView\b/, '<workbookView activeTab="' + idx + '" ');
          })();
          zip.file("xl/worksheets/sheet3.xml", sx);
          zip.file("xl/workbook.xml", wx);
          if (rx) zip.file("xl/worksheets/sheet4.xml", rx);
          return zip.generateAsync({ type: "uint8array", compression: "DEFLATE", compressionOptions: { level: 6 } });
        }).then(function (u8) { return { name: outName, bytes: u8 }; });
        });   // [b159] inchide _writeReferences(zip).then
      });
    });
  }

  // Buton dedicat: completeaza jurnalul oficial, il descarca DATAT si urca o copie in folderul perioadei.
  function downloadOfficialJournal(p) {
    if (!p) { toast("Nicio perioada activa.", "error"); return; }
    showAiLoading("Completez jurnalul oficial BETEL\u2026");
    hydrateStmtForClose(p).catch(function () {}).then(function () {
      var meta = (_lastStmtMeta && String(_lastStmtMeta.periodId) === String(p.Id)) ? _lastStmtMeta : null;
      return trxForZip(p).then(function (tx) {
        return buildOfficialJournal(p, tx || [], { endDate: (p.DataFinal ? isoDate(p.DataFinal) : null), lastStmtDate: (meta ? meta.dataFinal : null), stmtBalance: (meta && isFinite(meta.soldFinal) ? meta.soldFinal : null) });
      });
    }).then(function (off) {
      var blob = new Blob([off.bytes], { type: "application/vnd.openxmlformats-officedocument.spreadsheetml.sheet" });
      var url = URL.createObjectURL(blob);
      var a = document.createElement("a"); a.href = url; a.download = off.name;
      document.body.appendChild(a); a.click();
      setTimeout(function () { document.body.removeChild(a); URL.revokeObjectURL(url); }, 1000);
      var perRel = _siteRel + "/" + CONFIG.LIB.DOCS + "/" + periodLabel(p);
      return uploadFile(perRel, off.name, off.bytes)
        .then(function () { hideAiLoading(); toast("Jurnal oficial completat \u00ee salvat (\u201E" + off.name + "\u201D).", "success"); try { logEvent("actiune", "Jurnal oficial completat descarcat", off.name); } catch (e) {} })
        .catch(function (e) { hideAiLoading(); toast("Jurnal descarcat. Salvarea in SharePoint a esuat (vezi consola).", "warn"); console.warn("Jurnal oficial upload", e); });
    }).catch(function (e) {
      hideAiLoading(); console.error("Jurnal oficial", e);
      toast("Nu am putut completa jurnalul oficial: " + ((e && e.message) || "eroare"), "error");
    });
  }

  function zipPeriod(p, opts) {
    if (!p) return Promise.resolve();
    opts = opts || {};
    var label = periodLabel(p);
    // [b88] Numele arhivei/workbook-ului foloseste data de final aleasa (sugerata din extras) cand perioada e DESCHISA — nu „in-curs”.
    //   Citirea fisierelor ramane pe folderele reale (label/candidates).
    var nameLabel = isoDate(p.DataStart) + "_" + (opts.endDate ? opts.endDate : (p.DataFinal ? isoDate(p.DataFinal) : "in-curs"));
    // Incearca eticheta calculata, Title-ul SI folderul „_in-curs" (daca n-a fost redenumit la inchidere).
    var candidates = periodLabelsFor(p);
    if (!candidates.length) candidates = [label];
    var folderRel = _siteRel + "/" + CONFIG.LIB.DOCS + "/" + label;
    var folderUrl = location.origin + folderRel;
    showAiLoading("Pregatesc arhiva ZIP a perioadei…");

    // Aduna documentele din TOATE folderele candidate (ex. „_in-curs" + „_start_final"), dedup pe nume.
    // Orfanii (fisiere-document nerevendicate de nicio tranzactie a perioadei) sunt EXCLUSI si mutati in Cos.
    var got = [], gotNames = {}, orphans = [], periodTrx = null, orphRecycled = 0;
    // Perioada inchisa (are DataFinal): fisierele tranzactiilor de DUPA data inchiderii NU intra in arhiva
    // (apartin perioadei noi) si NU se sterg (se muta separat la reportare).
    var _cutD = p.DataFinal ? new Date(p.DataFinal) : null; if (_cutD) _cutD.setHours(23, 59, 59, 999);
    var _cutMs = _cutD ? _cutD.getTime() : null;
    var chain = hydrateStmtForClose(p).catch(function () {}).then(function () { return trxForZip(p); }).then(function (tx) { periodTrx = tx; });
    // [b102] aduna documentele din TOATE folderele perioadei (inclusiv „frate” start_*, daca au ramas nedupate dupa comasare), nu doar candidatele fixe
    chain = chain.then(function () { return expandedPeriodFolders(p); }).then(function (folders) {
      var _flist = (folders && folders.length) ? folders : candidates;
      var cc = Promise.resolve();
      _flist.forEach(function (lb) {
        cc = cc.then(function () {
          var rel = _siteRel + "/" + CONFIG.LIB.DOCS + "/" + lb;
          return listFolderFiles(rel).catch(function () { return []; }).then(function (files) {
          if (!files || !files.length) return;
          // Numele fisierelor revendicate de tranzactiile perioadei (null = nu am tranzactiile -> nu curatam).
          var keep = null, postCut = {}, skipZip = {};
          if (periodTrx) {
            keep = {};
            periodTrx.forEach(function (t) {
              var isPost = (_cutMs != null) && t.Data && !isNaN(new Date(t.Data).getTime()) && (new Date(t.Data).getTime() > _cutMs);
              var excl = zipExclude(t);
              filesForTrx(t, files).forEach(function (f) { var low = String(f.name || f.Name).toLowerCase(); if (isPost) postCut[low] = true; else if (excl) skipZip[low] = true; else keep[low] = true; });
              if (isPost || excl) return;
              // Protectie suplimentara: revendica si fisierele cu furnizor+nr.doc CURENT al tranzactiei.
              var furn = slug(t.Furnizor || "").toLowerCase();
              var nrd = slug((CONFIG.FIELDS.NR_DOC && t[CONFIG.FIELDS.NR_DOC]) || t.NrDoc || "").toLowerCase();
              if (furn && nrd && nrd.length > 1) {
                files.forEach(function (f) { var nm = String(f.Name).toLowerCase(); if (nm.indexOf(furn) === 0 && nm.indexOf(nrd) >= 0) keep[nm] = true; });
              }
            });
          }
          var c2 = Promise.resolve();
          files.forEach(function (f) {
            var low = String(f.Name).toLowerCase();
            if (gotNames[low]) return;                                   // deja adaugat din alt folder candidat
            if (/\.(xls|xlsx|zip)$/i.test(f.Name)) return;                // workbook/arhiva veche -> nu o bagam in ZIP
            if (low === RECON_CACHE_NAME) return;                         // cache intern extras reconciliat -> nu in ZIP
            if (postCut[low] && !keep[low]) return;                       // tranzactie de DUPA data inchiderii -> nu in arhiva, nu recycle
            if (skipZip[low] && !keep[low]) return;                       // storno / clarificare / de raportat -> nu in arhiva, nu recycle (merge mai departe)
            if (keep && !keep[low] && isDocName(f.Name)) { orphans.push(f); return; }   // orfan -> exclus + recycle
            gotNames[low] = true;
            c2 = c2.then(function () {
              return spGetBuffer("/_api/web/GetFileByServerRelativeUrl('" + spLit(f.ServerRelativeUrl) + "')/$value")
                .then(function (ab) { got.push({ name: f.Name, data: new Uint8Array(ab) }); })
                .catch(function (e) { console.warn("ZIP: nu am putut citi " + f.Name, e); delete gotNames[low]; });
            });
          });
          return c2;
        });
      });
    });
      return cc;
    });
    // Sterge automat orfanii (muta in Cos — recuperabil), best-effort.
    chain = chain.then(function () {
      var oc = Promise.resolve();
      orphans.forEach(function (f) {
        oc = oc.then(function () {
          return recycleFile(f.ServerRelativeUrl).then(function () { orphRecycled++; })
            .catch(function (e) { console.warn("ZIP: orfan nesters " + f.Name, e); });
        });
      });
      return oc.then(function () {
        if (orphRecycled) { try { logEvent("actiune", "ZIP: fisiere orfane mutate in cos (" + orphRecycled + ")", orphans.map(function (o) { return o.Name; }).join(", ")); } catch (x) {} }
      });
    });

    return chain.then(function () {
      var docCount = got.length;   // documentele perioadei (inainte de a adauga workbook-ul)
      var _officialName = null, _officialSaved = false;   // [b150] jurnal oficial BETEL completat
      // --- Folderul „de confirmat": copii ale documentelor decontate + mesajul .txt de confirmare ---
      var confItems = confirmItems(); var confDocs = 0, confMsg = false;
      if (confItems && confItems.length) {
        var want = {};
        // DOAR documentul principal (acelasi care apare in fila Tranzactii: factura > bon, NICIODATA chitanta card),
        // un singur fisier per document. fisiereAsociate() da numele (fara extensie); il potrivim cu fisierul real din folder.
        confItems.forEach(function (it) {
          var principal = fisiereAsociate(it.t);
          if (!principal) return;
          principal.split(" + ").map(function (s) { return s.trim().toLowerCase(); }).filter(Boolean).forEach(function (base) {
            for (var i = 0; i < got.length; i++) {
              var nmNoExt = String(got[i].name || "").toLowerCase().replace(/\.[a-z0-9]+$/i, "");
              if (nmNoExt === base) { want[got[i].name] = true; break; }   // primul = o singura copie principala
            }
          });
        });
        Object.keys(want).forEach(function (nm) {
          for (var i = 0; i < got.length; i++) { if (got[i].name === nm) { got.push({ name: "de confirmat/" + got[i].name, data: got[i].data }); confDocs++; break; } }
        });
        try {
          var ctxt = buildConfirmText(confItems);
          got.push({ name: "de confirmat/mesaj_confirmare.txt", data: new TextEncoder().encode("\ufeff" + ctxt) });
          confMsg = true;
        } catch (e) { console.error("confirm txt", e); try { logEvent("eroare", "ZIP: mesaj de confirmare esuat", (e && e.message) || ""); } catch (x) {} }
      }
      // [b150] .xls vechi (SpreadsheetML 2003, Tranzactii + Reconciliere) ELIMINAT din arhiva la
      //   cererea utilizatorului. Jurnalul oficial BETEL .xlsx (adaugat mai jos) il inlocuieste complet —
      //   are propriile file Tranzactii + Reconciliere, calculate de template, cu formulele intacte.
      var wbChain = Promise.resolve();
      return wbChain.then(function () {
        // [b150] Jurnalul oficial BETEL completat (datat) — adaugat la inceputul arhivei + urcat in folderul perioadei (best-effort).
        var _metaJ = (_lastStmtMeta && String(_lastStmtMeta.periodId) === String(p.Id)) ? _lastStmtMeta : null;
        return buildOfficialJournal(p, periodTrx || [], { endDate: opts.endDate, lastStmtDate: (_metaJ ? _metaJ.dataFinal : null), stmtBalance: (_metaJ && isFinite(_metaJ.soldFinal) ? _metaJ.soldFinal : null) })
          .then(function (off) {
            got.unshift({ name: off.name, data: off.bytes }); _officialName = off.name;
            return uploadFile(folderRel, off.name, off.bytes).then(function () { _officialSaved = true; }).catch(function (e) { console.warn("Jurnal oficial: upload esuat", e); });
          })
          .catch(function (e) { console.warn("Jurnal oficial: generare esuata", e); try { logEvent("avertisment", "Jurnal oficial necompletat la export", (e && e.message) || ""); } catch (x) {} });
      }).then(function () {
        var blob = makeZip(got); var url = URL.createObjectURL(blob);
        var a = document.createElement("a"); a.href = url; a.download = "Imprest_" + slug(nameLabel) + ".zip";
        document.body.appendChild(a); a.click();
        setTimeout(function () { document.body.removeChild(a); URL.revokeObjectURL(url); }, 1000);
        hideAiLoading();
        var _EN = (_lang === "en");   // [b120] dialogul de finalizare ZIP — limba interfetei
        var msg = _EN
          ? ((_officialName
                ? ("The archive contains the completed official BETEL journal \u201C" + _officialName + "\u201D" + (_officialSaved ? " (also saved to the period folder)" : ""))
                : "The archive could not include the official journal (see console)") +
             (docCount ? " + " + docCount + " document(s)" : (_officialName ? " (the folder had no uploaded documents)" : "")) +
             (confMsg ? (" + the \u201Cto confirm\u201D folder (" + confDocs + " document(s) + message)") : "") +
             (orphRecycled ? (" \u00B7 " + orphRecycled + " orphan file(s) excluded and moved to the Recycle Bin") : "") +
             ". If the download doesn't start, open the period folder.")
          : ((_officialName
                ? ("Arhiva contine jurnalul oficial BETEL completat \u201E" + _officialName + "\u201D" + (_officialSaved ? " (salvat si in folderul perioadei)" : ""))
                : "Arhiva nu a putut include jurnalul oficial (vezi consola)") +
             (docCount ? " + " + docCount + " document(e)" : (_officialName ? " (folderul nu avea documente incarcate)" : "")) +
             (confMsg ? (" + folderul \u201Ede confirmat\u201D (" + confDocs + " document(e) + mesaj)") : "") +
             (orphRecycled ? (" \u00B7 " + orphRecycled + " fisier(e) orfan(e) excluse si mutate in Cos") : "") +
             ". Daca descarcarea nu porneste, deschide folderul perioadei.");
        try { logEvent("actiune", "ZIP perioada descarcat (" + label + ")", docCount + " document(e)" + (_lastReconcileBlob ? " + reconciliere" : " (reconciliere fara extras)") + (confMsg ? (" + de confirmat (" + confDocs + ")") : "")); } catch (x) {}
        showDialog({
          title: _EN ? "ZIP archive downloaded" : "Arhiva ZIP descarcata", message: msg,
          confirmLabel: _EN ? "Open folder" : "Deschide folderul", cancelLabel: _EN ? "Close" : "Inchide", onConfirm: function () { window.open(folderUrl, "_blank"); }
        });
      });
    }).catch(function (e) { console.error(e); hideAiLoading(); toast("Eroare la crearea ZIP. Folder: " + folderUrl, "error"); });
  }

  /* ===========================================================================
     EXPORT (format 1-Transactions C:M) -> clipboard
     =========================================================================== */
  // [b91] Filtru pentru EXPORT: pastreaza doar tranzactiile care apartin perioadei pe extras.
  //   Exclude: (a) tranzactiile DUPA data extrasului/inchiderii (apartin perioadei urmatoare);
  //            (b) cheltuielile BANCARE care NU apar pe extras (nepotrivite, ne-blocate) — vor aparea pe extrasul urmator.
  //   Pastreaza mereu: numerar, alimentari/REPL (intrari), storno, „din imprestul trecut” si „blocate pe extras” (hold pe extras).
  //   Daca nu e extras incarcat: aplica doar taierea pe data (fara excludere dupa potrivire).
  function exportTrxFilter(rows) {
    var p = _activePeriod;
    var sm = (_lastStmtMeta && p && String(_lastStmtMeta.periodId) === String(p.Id)) ? _lastStmtMeta : null;
    var lr = (_lastReconcile && p && String(_lastReconcile.periodId) === String(p.Id)) ? _lastReconcile : null;
    var cutMs = null;
    var cd = (sm && sm.dataFinal) ? new Date(sm.dataFinal) : (p && p.DataFinal ? new Date(p.DataFinal) : null);
    if (cd && !isNaN(cd.getTime())) { cd.setHours(23, 59, 59, 999); cutMs = cd.getTime(); }
    var matched = null;
    if (lr && lr.matchedIds) { matched = {}; lr.matchedIds.forEach(function (id) { matched[String(id)] = 1; }); }
    return (rows || []).filter(function (t) {
      var td = t.Data ? new Date(t.Data).getTime() : NaN;
      if (cutMs != null && !isNaN(td) && td > cutMs) return false;     // dupa data extrasului -> perioada urmatoare
      if (!isBankTrx(t)) return true;                                  // numerar etc. raman
      var ti = tipInfo(t.TipTranzactie);
      if (ti && ti.io === "Intrari") return true;                      // alimentari / REPL
      if (Number(t.Suma || 0) < 0) return true;                        // storno
      if (isImprestTrecut(t)) return true;                             // din imprestul trecut (informativ)
      if (isBlocatExtras(t)) return true;                              // blocat pe extras (hold) -> apare pe extras
      if (matched && !matched[String(t.Id)]) return false;             // cheltuiala bancara care NU apare pe extras -> exclusa (perioada urmatoare)
      return true;
    });
  }

  // [b105] Ordinea tranzactiilor in TOATE exporturile (cerere utilizator):
  //   1) „din imprestul trecut” = ce era IN CURS DE CLARIFICARE data trecuta (acum decontate/complete) — PRIMELE, dupa data;
  //   2) restul tranzactiilor IN ORDINEA DE PE EXTRAS (reconciliere);
  //   3) ce nu e pe extras — la final, dupa Nr. crt.
  //   NU mai exista bloc separat de storno: stornourile intra in ordinea de pe extras (daca apar) sau la final.
  //   `rec` (optional, la inchidere) da ordinea de pe extras; altfel se foloseste _lastReconcile.matchedIds (aceeasi ordine).
  function exportTrxOrder(rows, rec) {
    var p = _activePeriod;
    var stmtOrder = {}, oi = 0;   // Id -> pozitia pe extras
    if (rec && rec.rows) { rec.rows.forEach(function (r) { if (r.t && r.t.Id != null && stmtOrder[String(r.t.Id)] == null) stmtOrder[String(r.t.Id)] = oi++; }); }
    else { var lr = (_lastReconcile && p && String(_lastReconcile.periodId) === String(p.Id) && _lastReconcile.matchedIds) ? _lastReconcile : null; if (lr) lr.matchedIds.forEach(function (id, idx) { stmtOrder[String(id)] = idx; }); }
    var hasStmt = false; for (var _k in stmtOrder) { hasStmt = true; break; }
    var byDataNr = function (a, b) { var da = new Date(a.Data).getTime() || 0, db = new Date(b.Data).getTime() || 0; return (da - db) || ((a.NrCrt || 0) - (b.NrCrt || 0)); };
    var byNrCrt = function (a, b) { return (a.NrCrt || 0) - (b.NrCrt || 0); };
    var gImpr = [], gStmt = [], gRest = [];
    (rows || []).forEach(function (t) {
      if (isImprestTrecut(t)) gImpr.push(t);
      else if (hasStmt && t.Id != null && stmtOrder[String(t.Id)] != null) gStmt.push(t);
      else gRest.push(t);
    });
    gImpr.sort(byDataNr);
    gStmt.sort(function (a, b) { return stmtOrder[String(a.Id)] - stmtOrder[String(b.Id)]; });
    gRest.sort(byNrCrt);
    return gImpr.concat(gStmt, gRest);
  }

  function buildExportText(decimal) {
    // C:M = Nr.crt | Metoda | Data | Tip | Nr.ref | Descriere | Cod furnizor | Suma | Cant | UOM | Descriere contabila
    var rows = exportTrxOrder(exportTrxFilter(_trx.slice()));
    var lines = rows.map(function (t, i) {
      var suma = String(Number(t.Suma || 0).toFixed(2));
      if (decimal === ",") suma = suma.replace(".", ",");
      return [
        (t.NrCrt || (i + 1)),
        t.MetodaPlata || "",
        fmtDate(t.Data, CONFIG.DATE_EXPORT),
        t.TipTranzactie || "",
        _nrRefX(t),   // [b172] cu fallback din buget
        descriereExport(t),
        t.CodFurnizor || "",
        suma,
        (t.Cantitate || 1),
        t.UOM || "ea",
        t.DescriereContabila || ""
      ].join("\t");
    });
    return lines.join("\n");
  }

  function xmlEsc(s) {
    return String(s == null ? "" : s).replace(/&/g, "&amp;").replace(/</g, "&lt;").replace(/>/g, "&gt;").replace(/"/g, "&quot;");
  }
  // Excel real (SpreadsheetML 2003 .xls) — coloane, antet bold, totaluri. Fara librarii externe.
  function buildExcelXml() {
    var rows = exportTrxOrder(exportTrxFilter(_trx.slice()));   // [b105] imprestul trecut (clarificare data trecuta) -> ordinea de pe extras -> rest
    var headers = ["Nr. crt", "Metoda de plata", "Data", "Tip tranzactie", "Nr. ref.",
      "Descriere", "Cod furnizor", "Suma (" + CONFIG.CURRENCY + ")", "Cantitate", "UOM", "Descriere contabila", "Fisiere asociate", "Observatii"];
    var widths = [50, 200, 78, 150, 70, 280, 100, 95, 70, 50, 220, 260, 220];

    function cellTxt(v) { return '<Cell ss:StyleID="sBody"><Data ss:Type="String">' + xmlEsc(v) + "</Data></Cell>"; }
    function cellNum(v) { return '<Cell ss:StyleID="sNum"><Data ss:Type="Number">' + Number(v || 0) + "</Data></Cell>"; }
    function cellDate(v) { return '<Cell ss:StyleID="sBody"><Data ss:Type="String">' + xmlEsc(fmtDate(v, "dd.mm.yyyy")) + "</Data></Cell>"; }

    var total = 0;
    var bodyRows = rows.map(function (t, i) {
      total += Number(t.Suma || 0);
      return "<Row>" +
        cellNum(t.NrCrt || (i + 1)) +
        cellTxt(t.MetodaPlata || "") +
        cellDate(t.Data) +
        cellTxt(t.TipTranzactie || "") +
        cellTxt(_nrRefX(t)) +   // [b172] cu fallback din buget
        cellTxt(descriereExport(t)) +
        cellTxt(t.CodFurnizor || "") +
        cellNum(t.Suma) +
        cellNum(t.Cantitate || 1) +
        cellTxt(t.UOM || "ea") +
        cellTxt(t.DescriereContabila || "") +
        cellTxt(fisiereAsociate(t)) +
        cellTxt((CONFIG.FIELDS.OBSERVATII && t[CONFIG.FIELDS.OBSERVATII]) || "") +
        "</Row>";
    }).join("");

    var headRow = "<Row ss:Height=\"22\">" + headers.map(function (h) {
      return '<Cell ss:StyleID="sHead"><Data ss:Type="String">' + xmlEsc(trText(h)) + "</Data></Cell>";   // [b115] antete EN
    }).join("") + "</Row>";

    var totalRow = '<Row><Cell ss:StyleID="sTotL"><Data ss:Type="String">TOTAL</Data></Cell>' +
      '<Cell ss:StyleID="sTotL"/><Cell ss:StyleID="sTotL"/><Cell ss:StyleID="sTotL"/><Cell ss:StyleID="sTotL"/>' +
      '<Cell ss:StyleID="sTotL"/><Cell ss:StyleID="sTotL"/>' +
      '<Cell ss:StyleID="sTotN"><Data ss:Type="Number">' + Number(total.toFixed(2)) + "</Data></Cell>" +
      '<Cell ss:StyleID="sTotL"/><Cell ss:StyleID="sTotL"/><Cell ss:StyleID="sTotL"/><Cell ss:StyleID="sTotL"/><Cell ss:StyleID="sTotL"/></Row>';

    var cols = widths.map(function (w) { return '<Column ss:Width="' + w + '"/>'; }).join("");
    var sheetName = (_activePeriod ? (_activePeriod.Title || periodLabel(_activePeriod)) : "Tranzactii").substring(0, 31);

    return '<?xml version="1.0"?>\n' +
      '<?mso-application progid="Excel.Sheet"?>\n' +
      '<Workbook xmlns="urn:schemas-microsoft-com:office:spreadsheet" ' +
      'xmlns:ss="urn:schemas-microsoft-com:office:spreadsheet">\n' +
      "<Styles>" +
      '<Style ss:ID="sHead"><Font ss:Bold="1" ss:Color="#FFFFFF" ss:Size="11"/>' +
      '<Interior ss:Color="#18293F" ss:Pattern="Solid"/>' +
      '<Alignment ss:Vertical="Center" ss:WrapText="1"/>' +
      '<Borders><Border ss:Position="Bottom" ss:LineStyle="Continuous" ss:Weight="1" ss:Color="#0F1B2B"/></Borders></Style>' +
      '<Style ss:ID="sBody"><Alignment ss:Vertical="Top" ss:WrapText="1"/>' +
      '<Borders><Border ss:Position="Bottom" ss:LineStyle="Continuous" ss:Weight="1" ss:Color="#E6EBF2"/></Borders></Style>' +
      '<Style ss:ID="sNum"><NumberFormat ss:Format="#,##0.00"/><Alignment ss:Vertical="Top"/>' +
      '<Borders><Border ss:Position="Bottom" ss:LineStyle="Continuous" ss:Weight="1" ss:Color="#E6EBF2"/></Borders></Style>' +
      '<Style ss:ID="sTotL"><Font ss:Bold="1"/><Interior ss:Color="#EEF2F7" ss:Pattern="Solid"/></Style>' +
      '<Style ss:ID="sTotN"><Font ss:Bold="1"/><NumberFormat ss:Format="#,##0.00"/><Interior ss:Color="#EEF2F7" ss:Pattern="Solid"/></Style>' +
      "</Styles>" +
      '<Worksheet ss:Name="' + xmlEsc(sheetName) + '">' +
      '<Table ss:DefaultRowHeight="15">' + cols + headRow + bodyRows + totalRow + "</Table>" +
      '<WorksheetOptions xmlns="urn:schemas-microsoft-com:office:excel">' +
      "<FreezePanes/><FrozenNoSplit/><SplitHorizontal>1</SplitHorizontal><TopRowBottomPane>1</TopRowBottomPane>" +
      "<ActivePane>2</ActivePane></WorksheetOptions>" +
      "</Worksheet></Workbook>";
  }

  function downloadExcel() {
    if (!_activePeriod || !_trx.length) { toast("Nicio tranzactie de exportat.", "error"); return; }
    // [b94] asigura reconcilierea (re-rulata din extrasul salvat) inainte de export, ca filtrul sa excluda corect
    //   cheltuielile care NU apar pe extras (ex. plata facuta vineri seara) chiar daca pagina a fost reincarcata.
    var _doDl = function () {
      var xml = buildExcelXml();
      var blob = new Blob(["\ufeff" + xml], { type: "application/vnd.ms-excel" });
      var url = URL.createObjectURL(blob);
      var a = document.createElement("a");
      a.href = url; a.download = "Imprest_" + slug(_activePeriod.Title || periodLabel(_activePeriod)) + ".xls";
      document.body.appendChild(a); a.click();
      setTimeout(function () { document.body.removeChild(a); URL.revokeObjectURL(url); }, 800);
      toast("Excel descarcat.", "success");
    };
    hydrateStmtForClose(_activePeriod).then(_doDl, _doDl);
  }

  /* ---- Excel cu situatia bugetelor (buget + conturi, detaliat) ---- */
  function buildBugeteExcelXml(cur, rate) {
    var usd = (cur === "USD");
    var unit = usd ? "USD" : CONFIG.CURRENCY;
    function conv(v) { return (v == null || isNaN(v)) ? v : (usd ? Number(v) / rate : Number(v)); }
    var headers = ["Buget", "Cod", "Tip", "Cont", "Alocat (" + unit + ")", "Cheltuit (" + unit + ")", "Disponibil (" + unit + ")", "Stare"];
    var widths = [200, 90, 90, 200, 110, 110, 110, 90];
    function cT(v, st) { return '<Cell ss:StyleID="' + (st || "sBody") + '"><Data ss:Type="String">' + xmlEsc(v == null ? "" : String(v)) + "</Data></Cell>"; }
    function cN(v, st) { return (v == null || isNaN(v)) ? cT("—", st) : '<Cell ss:StyleID="' + (st || "sNum") + '"><Data ss:Type="Number">' + Number(Number(conv(v)).toFixed(2)) + "</Data></Cell>"; }
    function stare(disp) { return isNaN(disp) ? "—" : (disp < 0 ? "Depasit" : "OK"); }

    var body = "";
    sortedBudgets().forEach(function (b) {
      var alocB = bugetAlocat(b.Title), consB = bugetConsumat(b.Title, null), dispB;
      if (!isNaN(alocB)) { dispB = alocB - consB; }
      else {
        var sumA = 0, any = false;
        conturiPtBuget(b.Title).forEach(function (c) { var a = contAlocat(b.Title, c.Title); if (!isNaN(a)) { sumA += a; any = true; } });
        if (any) { alocB = sumA; dispB = alocB - consB; } else { alocB = NaN; dispB = NaN; }
      }
      body += "<Row>" + cT(b.Title, "sB1") + cT(b.Cod || "", "sB1") + cT(b.Tip || "Buget", "sB1") + cT("— TOTAL —", "sB1") +
        cN(alocB, "sB1n") + cN(consB, "sB1n") + cN(dispB, "sB1n") + cT(stare(dispB), "sB1") + "</Row>";
      conturiPtBuget(b.Title).slice().sort(function (a, c) { return String(a.Title).localeCompare(String(c.Title)); }).forEach(function (c) {
        var a = contAlocat(b.Title, c.Title);
        var cons = contConsumat(b.Title, c.Title, null);
        var disp = isNaN(a) ? NaN : a - cons;
        body += "<Row>" + cT("") + cT("") + cT("") + cT(c.Title) + cN(a) + cN(cons) + cN(disp) + cT(stare(disp)) + "</Row>";
      });
    });

    var headRow = "<Row ss:Height=\"22\">" + headers.map(function (hh) {
      return '<Cell ss:StyleID="sHead"><Data ss:Type="String">' + xmlEsc(hh) + "</Data></Cell>";
    }).join("") + "</Row>";
    var cols = widths.map(function (w) { return '<Column ss:Width="' + w + '"/>'; }).join("");

    return '<?xml version="1.0"?>\n<?mso-application progid="Excel.Sheet"?>\n' +
      '<Workbook xmlns="urn:schemas-microsoft-com:office:spreadsheet" xmlns:ss="urn:schemas-microsoft-com:office:spreadsheet">\n' +
      "<Styles>" +
      '<Style ss:ID="sHead"><Font ss:Bold="1" ss:Color="#FFFFFF" ss:Size="11"/><Interior ss:Color="#18293F" ss:Pattern="Solid"/><Alignment ss:Vertical="Center" ss:WrapText="1"/></Style>' +
      '<Style ss:ID="sBody"><Alignment ss:Vertical="Top" ss:WrapText="1"/><Borders><Border ss:Position="Bottom" ss:LineStyle="Continuous" ss:Weight="1" ss:Color="#E6EBF2"/></Borders></Style>' +
      '<Style ss:ID="sNum"><NumberFormat ss:Format="#,##0.00"/><Alignment ss:Vertical="Top"/><Borders><Border ss:Position="Bottom" ss:LineStyle="Continuous" ss:Weight="1" ss:Color="#E6EBF2"/></Borders></Style>' +
      '<Style ss:ID="sB1"><Font ss:Bold="1"/><Interior ss:Color="#EEF2F7" ss:Pattern="Solid"/></Style>' +
      '<Style ss:ID="sB1n"><Font ss:Bold="1"/><NumberFormat ss:Format="#,##0.00"/><Interior ss:Color="#EEF2F7" ss:Pattern="Solid"/></Style>' +
      "</Styles>" +
      '<Worksheet ss:Name="Bugete (' + unit + ')"><Table ss:DefaultRowHeight="15">' + cols + headRow + body + "</Table>" +
      '<WorksheetOptions xmlns="urn:schemas-microsoft-com:office:excel"><FreezePanes/><FrozenNoSplit/><SplitHorizontal>1</SplitHorizontal><TopRowBottomPane>1</TopRowBottomPane><ActivePane>2</ActivePane></WorksheetOptions>' +
      "</Worksheet></Workbook>";
  }

  function downloadBugeteExcel() {
    if (!_bugete.length) { toast("Niciun buget de exportat.", "error"); return; }
    // Intreaba moneda (RON / USD) + cursul (implicit cel curent).
    var wrap = ce("div", "dlg-wrap"); var dlg = ce("div", "dlg");
    function closeWrap() { if (wrap.parentNode) wrap.parentNode.removeChild(wrap); }
    var h = document.createElement("div"); h.className = "h"; txt(h, "Export bugete — moneda"); dlg.appendChild(h);
    var bd = document.createElement("div"); bd.className = "b";
    var seg = ce("div", "seg"); var chosen = { cur: "RON" };
    var bRon = ce("button", "seg-b on"); bRon.type = "button"; txt(bRon, "RON");
    var bUsd = ce("button", "seg-b"); bUsd.type = "button"; txt(bUsd, "USD");
    bRon.addEventListener("click", function () { chosen.cur = "RON"; bRon.classList.add("on"); bUsd.classList.remove("on"); });
    bUsd.addEventListener("click", function () { chosen.cur = "USD"; bUsd.classList.add("on"); bRon.classList.remove("on"); });
    seg.appendChild(bRon); seg.appendChild(bUsd);
    var sFld = ce("div", "field"); var sl = document.createElement("label"); txt(sl, "Moneda"); sFld.appendChild(sl); sFld.appendChild(seg); bd.appendChild(sFld);
    var rFld = ce("div", "field"); var rl = document.createElement("label"); txt(rl, "Curs USD (RON/USD) — folosit doar daca alegi USD"); rFld.appendChild(rl);
    var rIn = input("number", _usdRate); rIn.step = "0.0001"; rIn.min = "0"; rFld.appendChild(rIn); bd.appendChild(rFld);
    var hint = ce("div", "hint"); txt(hint, "Azi: 1 USD = " + fmtBani(_usdRate) + " RON. Conversia o face aplicatia."); bd.appendChild(hint);
    dlg.appendChild(bd);
    var f = document.createElement("div"); f.className = "f";
    var cancel = ce("button", "btn ghost"); txt(cancel, "Anuleaza"); cancel.addEventListener("click", closeWrap);
    var ok = ce("button", "btn accent"); txt(ok, "Descarca");
    ok.addEventListener("click", function () {
      var rate = Number(rIn.value);
      if (chosen.cur === "USD" && (isNaN(rate) || rate <= 0)) { toast("Curs invalid.", "error"); return; }
      closeWrap();
      var xml = buildBugeteExcelXml(chosen.cur, rate);
      var blob = new Blob(["\ufeff" + xml], { type: "application/vnd.ms-excel" });
      var url = URL.createObjectURL(blob);
      var a = document.createElement("a");
      a.href = url; a.download = "Imprest_Bugete_" + chosen.cur + "_" + isoDate(new Date()) + ".xls";
      document.body.appendChild(a); a.click();
      setTimeout(function () { document.body.removeChild(a); URL.revokeObjectURL(url); }, 800);
      toast("Excel bugete (" + chosen.cur + ") descarcat.", "success");
    });
    f.appendChild(cancel); f.appendChild(ok); dlg.appendChild(f);
    wrap.addEventListener("click", function (e) { if (e.target === wrap) closeWrap(); });
    wrap.appendChild(dlg); el(APP_ID + "-app").appendChild(wrap);
  }

  function openExport() {
    if (!_activePeriod || !_trx.length) { toast("Nicio tranzactie de exportat.", "error"); return; }
    var wrap = ce("div", "dlg-wrap"); var dlg = ce("div", "dlg"); dlg.style.maxWidth = "640px";
    var h = document.createElement("div"); h.className = "h"; txt(h, "Export jurnal (ZIP, Excel, confirmare)"); dlg.appendChild(h);
    var bd = document.createElement("div"); bd.className = "b";
    var zipBtn = ce("button", "btn accent"); zipBtn.type = "button"; zipBtn.style.width = "100%"; txt(zipBtn, "⬇ Descarca ZIP (jurnal + documente)");
    zipBtn.addEventListener("click", function () { zipPeriodPrompt(_activePeriod); });
    bd.appendChild(zipBtn);
    var zipHint = ce("div", "hint"); txt(zipHint, "Livrabilul complet: jurnalul (pe TOATA perioada, chiar fara CSV) + toate documentele. Daca ai incarcat extrasul, ZIP-ul include si fila de reconciliere si folderul de confirmat."); zipHint.style.margin = "6px 0 10px"; bd.appendChild(zipHint);
    var confBtn = ce("button", "btn ghost"); confBtn.type = "button"; confBtn.style.width = "100%"; confBtn.style.marginBottom = "12px"; txt(confBtn, "📋 Copiaza mesajul de confirmare");
    confBtn.addEventListener("click", function () {
      var items = confirmItems();
      if (!items || !items.length) { toast("Nicio tranzactie completa cu document pentru confirmare.", "error"); return; }
      var data = buildConfirmText(items);
      function done() { toast("Mesaj de confirmare copiat (" + items.length + " documente).", "success"); }
      function fb() { try { var ta = document.createElement("textarea"); ta.value = data; document.body.appendChild(ta); ta.select(); document.execCommand("copy"); document.body.removeChild(ta); done(); } catch (e) { toast("Nu am putut copia automat.", "error"); } }
      if (navigator.clipboard) navigator.clipboard.writeText(data).then(done, fb); else fb();
    });
    bd.appendChild(confBtn);
    var pasteLbl = ce("div", "hint"); txt(pasteLbl, "Sau copiaza doar randurile pentru lipit manual in Excel (celula C12):"); pasteLbl.style.margin = "2px 0 6px"; bd.appendChild(pasteLbl);
    var seg = ce("div", "seg");
    var area = document.createElement("textarea"); area.readOnly = true;
    function refresh(dec) { area.value = buildExportText(dec); }
    var bComma = document.createElement("button"); txt(bComma, "Zecimale cu virgula (RO)"); bComma.className = "is-active";
    var bDot = document.createElement("button"); txt(bDot, "Zecimale cu punct");
    bComma.addEventListener("click", function () { bComma.className = "is-active"; bDot.className = ""; refresh(","); });
    bDot.addEventListener("click", function () { bDot.className = "is-active"; bComma.className = ""; refresh("."); });
    seg.appendChild(bComma); seg.appendChild(bDot);
    bd.appendChild(seg);
    var hint = ce("div", "hint"); txt(hint, "Coloanele sunt in ordinea C→M. Selecteaza C12 in Excel si lipeste (Ctrl+V)."); hint.style.margin = "8px 0"; bd.appendChild(hint);
    bd.appendChild(area); dlg.appendChild(bd);
    var f = document.createElement("div"); f.className = "f";
    var close = ce("button", "btn ghost"); txt(close, "Inchide"); close.addEventListener("click", function () { wrap.parentNode.removeChild(wrap); });
    var dl = ce("button", "btn"); txt(dl, "⬇ Descarca Excel (.xls)"); dl.addEventListener("click", downloadExcel);
    var copy = ce("button", "btn accent"); txt(copy, "Copiaza pt. HUB");
    copy.addEventListener("click", function () {
      area.select();
      if (navigator.clipboard) navigator.clipboard.writeText(area.value).then(function () { toast("Copiat in clipboard.", "success"); }, fallbackCopy);
      else fallbackCopy();
      function fallbackCopy() { try { document.execCommand("copy"); toast("Copiat.", "success"); } catch (e) { toast("Selecteaza si copiaza manual.", "error"); } }
    });
    f.appendChild(close); f.appendChild(dl); f.appendChild(copy); dlg.appendChild(f);
    if (!tabMountInline(dlg, [close])) { wrap.appendChild(dlg); el(APP_ID + "-app").appendChild(wrap); }
    refresh(CONFIG.DECIMAL_EXPORT);
    // [b94] re-randeaza dupa ce reconcilierea e re-rulata din extrasul salvat, ca paste-ul sa excluda corect
    //   cheltuielile care NU apar pe extras (chiar daca pagina a fost reincarcata si reconcilierea nu era in memorie).
    hydrateStmtForClose(_activePeriod).then(function () { refresh(bDot.className.indexOf("is-active") >= 0 ? "." : CONFIG.DECIMAL_EXPORT); }).catch(function () {});
  }

  /* ===========================================================================
     RECONCILIERE EXTRAS DE CONT (CSV / XML camt.053 / PDF-paste)
     Citeste tranzactiile din extras, le potriveste cu cele din jurnal dupa
     suma + data, marcheaza in Excel cele fara document justificativ si cele
     din extras care nu au corespondent. Totul client-side (fara AI, fara CORS),
     deci limba extrasului nu conteaza.
     =========================================================================== */
  function numRO(s) {
    s = String(s == null ? "" : s).replace(/[^\d.,\-]/g, "").trim();
    if (!s) return NaN;
    var neg = s.indexOf("-") >= 0; s = s.replace(/-/g, "");
    var lc = s.lastIndexOf(","), ld = s.lastIndexOf("."), dec = Math.max(lc, ld);
    var val;
    if (dec >= 0) { val = parseFloat(s.slice(0, dec).replace(/[.,]/g, "") + "." + s.slice(dec + 1).replace(/[.,]/g, "")); }
    else { val = parseFloat(s.replace(/[.,]/g, "")); }
    if (isNaN(val)) return NaN; return neg ? -val : val;
  }
  function parseDateAny(s) {
    s = String(s || "").trim(); var m;
    if ((m = s.match(/(\d{4})-(\d{1,2})-(\d{1,2})/))) return new Date(+m[1], +m[2] - 1, +m[3]);
    if ((m = s.match(/(\d{1,2})[.\/](\d{1,2})[.\/](\d{2,4})/))) { var y = +m[3]; if (y < 100) y += 2000; return new Date(y, +m[2] - 1, +m[1]); }
    return null;
  }
  function splitDelim(line, d) {
    var out = [], cur = "", q = false;
    for (var i = 0; i < line.length; i++) {
      var ch = line[i];
      if (ch === '"') { if (q && line[i + 1] === '"') { cur += '"'; i++; } else q = !q; }
      else if (ch === d && !q) { out.push(cur); cur = ""; }
      else cur += ch;
    }
    out.push(cur); return out;
  }
  // Extrage numele comerciantului din descrierea BT POS (intre TID si " RO/ROM <cifre>").
  // Ex.: "...TID:2PC4Y201 SOMES  BUCURESTI SEC RO 42449290..." -> "SOMES BUCURESTI SEC".
  function extractMerchant(desc) {
    var s = String(desc || "");
    var m = s.match(/TID[:\s]+\S+\s+(.+?)\s+(?:RO|ROM)\s+\d/i);
    if (m && m[1]) return m[1].replace(/\s{2,}/g, " ").trim();
    // Transfer intern: "...AVANS MNT DRAGHICI COSMIN; ORG..." -> ia textul de dinaintea primului ';'
    m = s.match(/^([^;]{3,}?)\s*;/);
    if (m && m[1] && !/POS|EPOS/i.test(m[1])) return m[1].replace(/\s{2,}/g, " ").trim();
    return "";
  }
  function parseStatementCSV(text) {
    var lines = text.split(/\r?\n/).filter(function (l) { return l.trim().length; });
    if (!lines.length) return [];
    var d = (lines[0].split(";").length > lines[0].split(",").length) ? ";" : (lines[0].indexOf("\t") >= 0 ? "\t" : ",");
    var rows = lines.map(function (l) { return splitDelim(l, d); });
    function norm(c) { return slug(c).toLowerCase(); }
    function rowHasCol(rowArr, keys) {
      for (var i = 0; i < rowArr.length; i++) { var h = norm(rowArr[i]); for (var k = 0; k < keys.length; k++) if (h.indexOf(keys[k]) >= 0) return i; }
      return -1;
    }
    // Cauta randul de antet oriunde in primele ~25 randuri (extrasul BT are preambul cu metadate).
    var headIdx = -1;
    for (var ri = 0; ri < Math.min(rows.length, 25); ri++) {
      var hasDate = rowHasCol(rows[ri], ["data"]) >= 0 || rowHasCol(rows[ri], ["date"]) >= 0;
      var hasMoney = rowHasCol(rows[ri], ["debit"]) >= 0 || rowHasCol(rows[ri], ["credit"]) >= 0 || rowHasCol(rows[ri], ["suma"]) >= 0 || rowHasCol(rows[ri], ["amount"]) >= 0;
      if (hasDate && hasMoney) { headIdx = ri; break; }
    }
    var out = [];
    if (headIdx >= 0) {
      var head = rows[headIdx].map(norm);
      function col(keys) { for (var i = 0; i < head.length; i++) for (var k = 0; k < keys.length; k++) if (head[i].indexOf(keys[k]) >= 0) return i; return -1; }
      // "data tranzactie" preferat fata de "data valuta"
      var iDate = col(["data tranzactie", "data-tranzactie"]); if (iDate < 0) iDate = col(["data", "date"]);
      var iDeb = col(["debit", "iesir", "deb"]), iCred = col(["credit", "intrar", "incasar", "cred"]),
          iAmt = col(["suma", "amount", "valoare"]),
          iRef = col(["referinta", "referinta", "ref"]),
          iTip = col(["tip tranzactie", "tip-tranzactie", "tip"]),
          iDesc = col(["descriere", "detalii", "details", "explicat", "naratiune", "narativ", "info"]);
      rows.slice(headIdx + 1).forEach(function (r) {
        var dt = iDate >= 0 ? parseDateAny(r[iDate]) : null;
        var amt = NaN;
        if (iAmt >= 0 && r[iAmt] != null && String(r[iAmt]).trim()) amt = numRO(r[iAmt]);
        if (isNaN(amt) && iDeb >= 0 && String(r[iDeb] || "").trim()) { var dv = numRO(r[iDeb]); if (!isNaN(dv) && dv !== 0) amt = -Math.abs(dv); }
        if (isNaN(amt) && iCred >= 0 && String(r[iCred] || "").trim()) { var cv = numRO(r[iCred]); if (!isNaN(cv) && cv !== 0) amt = Math.abs(cv); }
        var rich = iDesc >= 0 ? String(r[iDesc] || "").trim() : "";
        var tip = iTip >= 0 ? String(r[iTip] || "").trim() : "";
        var ref = iRef >= 0 ? String(r[iRef] || "").trim() : "";
        var merchant = extractMerchant(rich);
        // Descrierea afisata: tipul + textul detaliat (fara duplicare).
        var desc = rich || tip;
        if (tip && rich && rich.toLowerCase().indexOf(tip.toLowerCase()) < 0) desc = tip + " — " + rich;
        if (dt && !isNaN(amt) && amt !== 0) out.push({ date: dt, amount: amt, desc: desc, ref: ref, merchant: merchant });
      });
      if (out.length) return out;
    }
    // Fallback (fara antet clar): heuristic pe randul brut, dar ignora token-uri lungi gen RRN/Ref.
    rows.forEach(function (r) {
      var dt = null; r.forEach(function (c) { if (!dt) { var p = parseDateAny(c); if (p) dt = p; } });
      // candidati de suma: doar numere "rezonabile" (cu zecimale sau <= 6 cifre), evitand RRN-uri lungi
      var amt = NaN; r.forEach(function (c) {
        var raw = String(c || "").trim(); if (!/^[\d.,\-\s]+$/.test(raw)) return; // doar campuri pur numerice
        var n = numRO(raw); if (isNaN(n) || n === 0) return;
        var digits = raw.replace(/\D/g, ""); if (digits.length > 9) return; // exclude RRN/cont lung
        if (isNaN(amt) || Math.abs(n) > Math.abs(amt)) amt = n;
      });
      var desc = ""; r.forEach(function (c) { var s = String(c || "").trim(); if (s.length > desc.length && isNaN(numRO(s.replace(/\s/g, ""))) && !parseDateAny(s)) desc = s; });
      if (dt && !isNaN(amt) && amt !== 0) out.push({ date: dt, amount: amt, desc: desc, ref: "", merchant: extractMerchant(desc) });
    });
    return out;
  }
  // Citeste metadatele din preambulul extrasului BT: sold initial/final, sume blocate, perioada.
  // Robust la delimitator si la etichetele cu ":" si majuscule.
  function parseStatementMeta(text) {
    var lines = String(text || "").split(/\r?\n/);
    var meta = { soldInitial: NaN, soldFinal: NaN, blocat: NaN, dataStart: null, dataFinal: null };
    lines.forEach(function (l) {
      if (!l.trim()) return;
      var d = (l.split(";").length > l.split(",").length) ? ";" : ",";
      var cells = splitDelim(l, d);
      if (cells.length < 2) return;
      var key = String(cells[0] || "").toLowerCase().replace(/[^a-z]+/g, " ").trim();
      var val = cells[1];
      if (key === "sold initial") meta.soldInitial = numRO(val);
      else if (key.indexOf("sold final") === 0) meta.soldFinal = numRO(val);   // "sold final cont"
      else if (key.indexOf("sume blocate") === 0) meta.blocat = numRO(val);
      else if (key === "de la") meta.dataStart = parseDateAny(val);
      else if (key === "pana la") meta.dataFinal = parseDateAny(val);
    });
    return meta;
  }
  // [v2-b50] Extras in afara perioadei? Extrasele dinaintea startului (sau de dupa inchidere) apartin
  // altui imprest si ar lega/crea gresit tranzactii. Intoarce motivul (text) sau null daca e in regula.
